window.SILA_ARTICLES["gujarati_2004"]={"meta": {"key": "gujarati_2004", "title": "Econometría — Parte I: Modelos de regresión uniecuacionales (Capítulos 1-6)", "authors": "Damodar N. Gujarati", "year": 2004, "category": "Métodos Cuantitativos", "weight": "critico", "journal": "McGraw-Hill (Libro de texto, 4ª edición)", "institution": "United States Military Academy, West Point", "fidelity": 99.0, "cards": 35, "concepts": 15, "highlights": {"authors": ["Gujarati", "Galton", "Gauss", "Markov", "Fisher", "Student", "Pearson", "Goldberger", "Keynes", "Friedman", "Phillips", "Engel", "Jarque", "Bera", "Rao"], "terms": ["análisis de regresión", "mínimos cuadrados ordinarios", "función de regresión poblacional", "función de regresión muestral", "perturbación estocástica", "mejor estimador lineal insesgado", "teorema de Gauss-Markov", "modelo clásico de regresión lineal", "homocedasticidad", "heterocedasticidad", "autocorrelación", "intervalo de confianza", "prueba de hipótesis", "distribución t", "distribución F", "coeficiente de determinación", "error estándar", "nivel de significancia", "valor p", "grados de libertad", "ANOVA", "elasticidad"], "key": ["la regresión trata del estudio de la dependencia de una variable respecto de una o más variables", "el objetivo del análisis de regresión es estimar el valor medio de la variable dependiente", "los estimadores de MCO son los mejores estimadores lineales insesgados", "la prueba de significancia es un procedimiento mediante el cual los resultados muestrales se utilizan para verificar la verdad o falsedad de una hipótesis nula", "el coeficiente de determinación mide la proporción de la variación total explicada por la regresión"], "examples": ["relación estatura padres-hijos de Galton", "gasto de consumo e ingreso", "curva de Phillips", "función de consumo keynesiana", "Ley de Engel"]}, "downloads": {"docx": "downloads/articles/SILA_Gujarati_2004.docx", "fuente": "downloads/articles/Gujarati_2004_fuente.txt"}}, "prelectura": {"posicionamiento": [{"q": "¿A qué debate responde este texto?", "a": "Este texto responde al debate sobre cómo cuantificar relaciones entre variables económicas. Gujarati presenta la econometría como la disciplina que permite validar empíricamente las teorías económicas mediante el análisis estadístico de datos reales, superando la limitación de los modelos puramente teóricos."}, {"q": "¿Con quién dialoga?", "a": "Dialoga con la tradición estadística de Galton (regresión), Gauss y Markov (propiedades de estimadores), Fisher (pruebas de hipótesis) y la tradición económica keynesiana (función de consumo). También con los debates metodológicos sobre la relación entre teoría económica y evidencia empírica."}, {"q": "¿Qué gap llena?", "a": "Llena el gap entre la teoría económica abstracta y su verificación empírica. Sin econometría, las relaciones entre variables económicas quedan como proposiciones teóricas no verificables. Los capítulos 1-6 construyen desde cero las herramientas para estimar, evaluar y predecir con el modelo de regresión lineal."}, {"q": "¿Cuál es la tradición teórica?", "a": "Se ubica en la tradición positivista/empirista de la ciencia económica, donde las proposiciones teóricas deben ser contrastadas con datos observados. Metodológicamente sigue la tradición frecuentista de inferencia estadística (Fisher, Neyman-Pearson)."}, {"q": "¿Cuál es la relevancia doctoral?", "a": "Fundamental para cualquier investigación doctoral que utilice datos cuantitativos. Dominar el modelo de regresión lineal es prerequisito para métodos más avanzados (panel data, series de tiempo, modelos no lineales). Permite evaluar críticamente la evidencia empírica en la literatura."}], "esqueleto": {"tesis": "Gujarati demuestra que el análisis de regresión lineal, fundamentado en el método de Mínimos Cuadrados Ordinarios (MCO) y los supuestos del Modelo Clásico de Regresión Lineal (MCRL), proporciona un marco riguroso y completo para estimar relaciones entre variables, realizar inferencia estadística y generar predicciones — siempre que se cumplan los supuestos fundamentales del modelo.", "pasos": [{"paso": "PASO 1", "desc": "Establece la naturaleza y origen del análisis de regresión: dependencia estadística (no determinista) entre variables, distinguiendo regresión de correlación y causalidad.", "ref": "§Cap. 1"}, {"paso": "PASO 2", "desc": "Introduce el modelo poblacional (FRP) y muestral (FRM), la perturbación estocástica y el concepto de linealidad en parámetros.", "ref": "§Cap. 2"}, {"paso": "PASO 3", "desc": "Desarrolla MCO como método de estimación: derivación de fórmulas, propiedades numéricas y estadísticas, teorema de Gauss-Markov (MELI).", "ref": "§Cap. 3"}, {"paso": "PASO 4", "desc": "Añade el supuesto de normalidad (MCRLN), habilitando distribuciones exactas (t, F, chi-cuadrado) para inferencia.", "ref": "§Cap. 4"}, {"paso": "PASO 5", "desc": "Construye intervalos de confianza y pruebas de hipótesis usando las distribuciones del paso anterior. Introduce ANOVA y predicción.", "ref": "§Cap. 5"}, {"paso": "PASO 6", "desc": "Extiende el modelo básico: regresión por el origen, transformaciones logarítmicas, modelos semilogarítmicos, recíprocos y elección de forma funcional.", "ref": "§Cap. 6"}]}, "resumen": [{"sec": "Cap. 1: Naturaleza de la regresión", "desc": "Origen histórico (Galton), regresión moderna como análisis de dependencia estadística, relación con correlación y causalidad, tipos de datos.", "ref": "pp. 13-33"}, {"sec": "Cap. 2: Ideas básicas", "desc": "Modelo poblacional (FRP) vs muestral (FRM), perturbación estocástica, linealidad en parámetros vs en variables.", "ref": "pp. 34-53"}, {"sec": "Cap. 3: Estimación MCO", "desc": "Derivación de MCO, propiedades numéricas, supuestos MCRL, teorema de Gauss-Markov, R², error estándar.", "ref": "pp. 55-97"}, {"sec": "Cap. 4: MCRLN", "desc": "Supuesto de normalidad, justificación por TLC, distribuciones exactas de estimadores, equivalencia con máxima verosimilitud.", "ref": "pp. 99-107"}, {"sec": "Cap. 5: Intervalos y pruebas", "desc": "Intervalos de confianza para β y σ², pruebas t y F, ANOVA, valor p, significancia estadística vs práctica, predicción.", "ref": "pp. 109-147"}, {"sec": "Cap. 6: Extensiones", "desc": "Regresión por el origen, cambio de escala, modelos log-lineales, semilog, recíprocos, elección de forma funcional.", "ref": "pp. 149-187"}, {"sec": "Hilo conductor", "desc": "Progresión lógica: definir → modelar → estimar → suponer normalidad → inferir → extender. Cada capítulo construye sobre el anterior.", "ref": "Caps. 1-6"}, {"sec": "Aplicaciones recurrentes", "desc": "Función de consumo keynesiana, curva de Phillips, Ley de Engel, CAPM, demanda de café — los mismos datos reaparecen con técnicas cada vez más sofisticadas.", "ref": "Caps. 1-6"}], "alertas": [{"n": 1, "texto": "Regresión NO implica causalidad. Gujarati lo advierte explícitamente, pero es el error más común. Una R² alta entre X e Y no significa que X cause Y. La dirección causal viene de la teoría, no de la estadística."}, {"n": 2, "texto": "Linealidad en parámetros ≠ linealidad en variables. Un modelo como Y = β₁X^β₂ es no lineal en variables pero puede ser lineal en parámetros tras una transformación logarítmica. Esta distinción es crítica para saber si MCO aplica."}, {"n": 3, "texto": "Los supuestos del MCRL son condiciones NECESARIAS para que MCO sea MELI (Gauss-Markov). Si se viola homocedasticidad o no-autocorrelación, MCO sigue siendo insesgado pero ya NO es eficiente — hay estimadores mejores."}, {"n": 4, "texto": "'No rechazar H₀' NO es lo mismo que 'aceptar H₀'. La lógica de la prueba de hipótesis es asimétrica: se puede refutar con evidencia pero no confirmar con certeza. Error tipo I y tipo II no son simétricos."}, {"n": 5, "texto": "Significancia estadística ≠ significancia práctica. Un coeficiente puede ser estadísticamente significativo (t > 2) pero económicamente trivial (efecto de 0.001%). Siempre evaluar la magnitud del efecto, no solo el valor p."}, {"n": 6, "texto": "R² NO es una medida de la calidad del modelo. Un R² bajo no invalida un modelo teóricamente sólido, y un R² alto puede ser espurio. En series de tiempo, R² tiende a ser alto artificialmente por la tendencia compartida."}], "citables": [{"uso": "📌 Definir", "cita": "El análisis de regresión trata del estudio de la dependencia de una variable, la variable dependiente, respecto de una o más variables, las variables explicativas, con el objetivo de estimar o predecir el valor medio de la primera.", "ref": "Gujarati (2004, Cap. 1)"}, {"uso": "🏛 Justificar", "cita": "El método de mínimos cuadrados ordinarios se atribuye a Carl Friedrich Gauss, quien lo desarrolló en 1809 para predecir órbitas planetarias. Su elegancia radica en que minimiza la suma de los cuadrados de las diferencias entre valores observados y estimados.", "ref": "Gujarati (2004, Cap. 3)"}, {"uso": "♻ Explicar", "cita": "Según el teorema de Gauss-Markov, dentro de la clase de estimadores lineales insesgados, los estimadores de MCO tienen varianza mínima; son los mejores estimadores lineales insesgados (MELI).", "ref": "Gujarati (2004, Cap. 3)"}, {"uso": "⚖ Debatir", "cita": "La significancia estadística de un coeficiente no debe confundirse con su significancia práctica o económica. Un coeficiente puede ser estadísticamente significativo y sin embargo tener un efecto sustantivamente pequeño.", "ref": "Gujarati (2004, Cap. 5)"}, {"uso": "🌱 Fundamentar", "cita": "El coeficiente de determinación R² mide la proporción o porcentaje de la variación total en Y explicada por el modelo de regresión. Sin embargo, un R² alto no es evidencia de causalidad ni de un buen modelo.", "ref": "Gujarati (2004, Cap. 3)"}, {"uso": "📌 Definir", "cita": "En el modelo log-lineal o doble logarítmico, el coeficiente de pendiente β₂ mide la elasticidad de Y respecto de X, es decir, el cambio porcentual en Y ante un cambio porcentual en X.", "ref": "Gujarati (2004, Cap. 6)"}, {"uso": "♻ Explicar", "cita": "La perturbación estocástica u representa todos los factores que afectan a Y pero que no están incluidos explícitamente en el modelo de regresión. Su presencia es inevitable porque ningún modelo puede capturar toda la complejidad de la realidad.", "ref": "Gujarati (2004, Cap. 2)"}, {"uso": "🏛 Justificar", "cita": "El supuesto de normalidad de los errores permite pasar del teorema de Gauss-Markov al resultado más fuerte: los estimadores MCO son no solo MELI sino los mejores estimadores insesgados (MEI) en toda la clase de estimadores, lineales o no.", "ref": "Gujarati (2004, Cap. 4)"}]}, "puente": [{"emoji": "🎯", "q": "¿Qué argumento de MI tesis respalda este texto?", "hint": "Piensa en qué relaciones cuantitativas necesitas estimar en tu investigación. Ej: 'La regresión múltiple me permite aislar el efecto de cada variable organizacional sobre el desempeño, controlando por las demás.'"}, {"emoji": "⚔️", "q": "¿Con qué posición teórica quiero debatir o matizar?", "hint": "Gujarati presenta los supuestos clásicos como condiciones ideales. ¿Qué sucede en tu contexto de investigación cuando estos supuestos se violan? ¿Tu fenómeno de estudio puede acomodarse al modelo lineal?"}, {"emoji": "🔍", "q": "¿Qué gap de investigación me revela este texto?", "hint": "Los capítulos 1-6 cubren el modelo bivariado. ¿Tu investigación requiere modelos multivariados, datos de panel, o métodos no paramétricos que van más allá de lo presentado aquí?"}, {"emoji": "📝", "q": "¿Cómo lo citaría en mi marco teórico?", "hint": "Ej: 'Siguiendo la metodología econométrica clásica (Gujarati, 2004), se estimará la relación entre X e Y mediante MCO, verificando los supuestos del MCRL mediante las pruebas de Jarque-Bera (normalidad) y...'"}, {"emoji": "❓", "q": "¿Qué sigo sin entender después de la pre-lectura?", "hint": "¿Entiendes la diferencia entre estimador e estimación? ¿Entre FRP y FRM? ¿Por qué MCO minimiza los cuadrados y no los valores absolutos? Registra tus dudas antes de leer."}], "sections": [{"title": "CAPÍTULO 1: NATURALEZA DEL ANÁLISIS DE REGRESIÓN", "paragraphs": [{"text": "Francis Galton acuñó el término regresión. En un famoso ensayo, Galton planteó que, a pesar de la tendencia de los padres de estatura alta a procrear hijos altos y los padres de estatura baja, hijos bajos, la estatura promedio de los niños de padres de una estatura determinada tendía a desplazarse, o \"regresar\", a la estatura promedio de la población total. En otras palabras, la estatura de los hijos de padres inusualmente altos o inusualmente bajos tiende a dirigirse a la estatura promedio de la población. La ley de regresión universal de Galton fue confirmada por su amigo Karl Pearson, quien reunió más de mil registros de estaturas de miembros de grupos familiares. Pearson descubrió que la estatura promedio de los hijos de un grupo de padres de estatura alta era menor que la estatura de sus padres, y que la estatura promedio de los hijos de un grupo de padres de estatura baja era mayor que la estatura de sus padres; es decir, se trata de un fenómeno mediante el cual los hijos altos e hijos bajos \"regresan\" por igual a la estatura promedio de todos los demás. En palabras de Galton, se trata de una \"regresión a la mediocridad\".", "title": "Origen histórico del término regresión según Galton", "eq": "¿Por qué Galton usó el término 'regresión' y cómo difiere este significado original del uso moderno en econometría?", "anns": [{"t": "◆◆◆ CRÍTICO:\nAUTOR / TEORÍA: Francis Galton (1886) acuñó 'regresión' al estudiar la herencia de estaturas. Su hallazgo fue que los hijos de padres extremos (muy altos o muy bajos) tendían a tener estaturas más cercanas al promedio poblacional, fenómeno que llamó 'regresión a la mediocridad'.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Imagine que en una universidad, los estudiantes con las calificaciones más altas en el primer examen tienden a obtener calificaciones un poco más bajas en el segundo (y viceversa). Esto no significa que 'empeoraron', sino que hay regresión a la media: el rendimiento extremo tiende a acercarse al promedio en observaciones subsecuentes.", "c": "1A5C38", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: Karl Pearson confirmó empíricamente la ley de Galton con más de 1,000 registros familiares. Pearson es también el padre del coeficiente de correlación, herramienta estrechamente ligada a la regresión.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El concepto de 'regresión a la media' reaparece en la sección 1.2 donde se redefine la regresión en términos modernos como estimación de medias condicionales.", "c": "2D2D8F", "b": true}]}, {"text": "La interpretación moderna de la regresión es, sin embargo, muy diferente. En términos generales, se afirma que:\nEl análisis de regresión trata del estudio de la dependencia de una variable (variable dependiente) respecto de una o más variables (variables explicativas) con el objetivo de estimar o predecir la media o valor promedio poblacional de la primera en términos de los valores conocidos o fijos (en muestras repetidas) de las segundas.", "title": "Definición moderna del análisis de regresión", "eq": "¿Qué significa exactamente 'estimar la media poblacional' y por qué el análisis de regresión se centra en promedios y no en valores individuales?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El análisis de regresión moderno busca estimar o predecir el valor PROMEDIO (media condicional) de la variable dependiente dados valores fijos de las variables explicativas. No predice valores individuales, sino tendencias centrales.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: La regresión moderna NO es la 'regresión a la media' de Galton. Galton buscaba explicar la estabilidad poblacional; la econometría moderna busca estimar relaciones funcionales entre variables.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si un banco quiere predecir cuánto gastará en promedio una familia con ingreso de $50,000 anuales, el análisis de regresión estima esa media condicional E(Gasto | Ingreso = 50,000), no el gasto de una familia específica.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Esta definición es la base de la Función de Regresión Poblacional (FRP) que se formaliza en el Capítulo 2, ecuación (2.2.1).", "c": "2D2D8F", "b": true}]}, {"text": "Considere de nuevo la ley de regresión universal de Galton. A él le interesaba averiguar las razones de la estabilidad en la distribución de estaturas dentro de una población. En el enfoque moderno, la preocupación no es esta explicación, sino averiguar cómo cambia la estatura promedio de los hijos dada la estatura de los padres. En otras palabras, lo que interesa es predecir la estatura promedio de los hijos a partir de la estatura de sus padres. Para ver cómo hacerlo, considere la figura 1.1, que corresponde a un diagrama de dispersión. La figura muestra la distribución de las estaturas de los hijos en una población hipotética, correspondiente al conjunto de valores dados o fijos de las estaturas de los padres. Observe que, para cualquier estatura de un padre, existe un rango (distribución) de estaturas de los hijos. Sin embargo, observe también que, a pesar de la variabilidad de la estatura de los hijos conforme al valor de la estatura de los padres, la estatura promedio de los hijos aumenta, por lo general, en la medida en que lo hace la estatura de los padres. Para demostrar esto con claridad, las cruces dentro de los círculos en la figura indican la estatura promedio de los hijos que corresponde a una estatura determinada de los padres. Estos promedios se conectan para obtener la línea recta de la figura. Esta línea, como veremos, se conoce como recta de regresión. Dicha recta muestra que el promedio de la estatura de los hijos aumenta conforme crece la de los padres.", "title": "El diagrama de dispersión y la recta de regresión", "eq": "¿Por qué la recta de regresión conecta las medias condicionales y no los valores individuales observados?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La recta de regresión es la línea que conecta las medias condicionales de Y (variable dependiente) para cada valor fijo de X (variable explicativa). Es la representación gráfica de E(Y|X).", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El diagrama de dispersión revela que para cada valor de X existe una DISTRIBUCIÓN de valores de Y, no un solo valor. La regresión resume esta distribución mediante su media.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: En un estudio de rendimiento académico, si graficamos las calificaciones finales (Y) contra horas de estudio (X), para cada nivel de horas habrá varios estudiantes con calificaciones diferentes. La recta de regresión conectará el promedio de calificaciones en cada nivel de horas.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El concepto de diagrama de dispersión con medias condicionales se formaliza en el Capítulo 2 con los datos de consumo-ingreso (tabla 2.1 y figura 2.1).", "c": "2D2D8F", "b": true}]}, {"text": "Al considerar lo referente a la economía, a un economista quizá le interese estudiar la dependencia del consumo personal respecto del ingreso personal neto disponible (después de impuestos). Con un análisis de este tipo se calcula la propensión marginal a consumir (PMC), es decir, el cambio promedio del consumo ante un cambio, digamos, de un dólar en el ingreso real. Un monopolista que puede fijar el precio o la producción (pero no ambos factores) tal vez desee conocer la demanda de un producto con diversos precios. Tal experimento permite estimar la elasticidad del precio (es decir, la respuesta a variaciones del precio) de la demanda del producto y permite determinar el precio que maximiza las ganancias. Un economista laboral quizá desee estudiar la tasa de cambio de los salarios monetarios o nominales en relación con la tasa de desempleo. Las cifras históricas aparecen en el diagrama de dispersión de la figura 1.3. La curva de esta figura es un ejemplo de la célebre curva de Phillips, que relaciona los cambios en los salarios nominales con la tasa de desempleo.", "title": "Aplicaciones económicas del análisis de regresión", "eq": "¿En qué se diferencia usar regresión para estimar la PMC versus simplemente calcular el cambio en consumo dividido entre el cambio en ingreso?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La propensión marginal a consumir (PMC) es el cambio promedio en el consumo por cada unidad adicional de ingreso. Es un coeficiente de regresión: el β₂ en la función consumo = β₁ + β₂(ingreso).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: La elasticidad precio de la demanda mide la respuesta porcentual de la cantidad demandada ante un cambio porcentual en el precio. Puede estimarse mediante regresión usando formas logarítmicas.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: La curva de Phillips (A.W. Phillips, 1958) relaciona la tasa de cambio de salarios nominales con la tasa de desempleo. Es una de las relaciones empíricas más estudiadas en macroeconomía, estimada típicamente mediante regresión.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: ¿Puede la regresión demostrar que el ingreso CAUSA el consumo, o solo muestra una asociación estadística? Esta pregunta se aborda en la sección 1.4 sobre regresión y causalidad.", "c": "7B5800", "b": true}]}, {"text": "En los ejemplos de la sección 1.2 se observa que en el análisis de regresión interesa lo que se conoce como dependencia estadística entre variables, no así la funcional o determinista, propia de la física clásica. En las relaciones estadísticas entre variables se analizan, en esencia, variables aleatorias o estocásticas, es decir, variables con distribuciones de probabilidad. Por otra parte, en la dependencia funcional o determinista también se manejan variables, pero no son aleatorias o estocásticas.", "title": "Dependencia estadística versus dependencia determinista", "eq": "¿Por qué las relaciones económicas son inherentemente estadísticas y no deterministas como las leyes de la física?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Relación ESTADÍSTICA = variables aleatorias con distribución de probabilidad, predicción inexacta. Relación DETERMINISTA = variables fijas, predicción exacta (ej: F = k·m₁m₂/r²). La econometría trabaja con relaciones estadísticas.", "c": "C00000", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Una variable estocástica (del griego stokhos, 'centro del blanco') es una variable que toma valores con una probabilidad dada. En la regresión, la variable dependiente Y es estocástica porque no puede predecirse con certeza.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: La ley de Ohm (C = V/R) es determinista: dado el voltaje y la resistencia, la corriente es exacta. En cambio, la relación consumo-ingreso es estadística: familias con el mismo ingreso tienen consumos diferentes debido a gustos, composición familiar, etc.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: La naturaleza estocástica de la regresión se formaliza en el Capítulo 2 con la introducción del término de perturbación uᵢ en la ecuación (2.4.1).", "c": "2D2D8F", "b": true}]}, {"text": "Por ejemplo, el rendimiento de un cultivo depende de la temperatura, lluvia, Sol y fertilizantes, y dicha dependencia es de naturaleza estadística porque las variables explicativas, si bien son importantes, no permiten al agrónomo predecir en forma exacta el rendimiento del cultivo debido a los errores propios de la medición de estas variables y a otra serie de factores (variables) que en conjunto afectan el rendimiento pero son difíciles de identificar individualmente. De esta manera, habrá alguna variabilidad \"intrínseca\" o aleatoria en la variable dependiente, el rendimiento del cultivo, que no puede explicarse en su totalidad sin importar cuántas variables explicativas se consideren.", "title": "Variabilidad intrínseca en relaciones estadísticas", "eq": "¿Es posible eliminar completamente la variabilidad aleatoria en un modelo de regresión agregando más variables explicativas?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La variabilidad intrínseca o aleatoria significa que SIEMPRE habrá una parte del comportamiento de Y que no puede explicarse, sin importar cuántas variables X se incluyan. Esta variabilidad se captura mediante el término de error uᵢ.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Reconocer la variabilidad intrínseca implica que un modelo de regresión NUNCA tendrá R² = 1 (ajuste perfecto) en datos reales. Buscar un ajuste perfecto puede llevar a sobreajuste.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las razones específicas de esta variabilidad se desarrollan en el Capítulo 2, sección 2.5, donde se enumeran 7 razones para la existencia del término de perturbación estocástica.", "c": "2D2D8F", "b": true}]}, {"text": "A pesar de que el análisis de regresión tiene que ver con la dependencia de una variable respecto de otras variables, esto no implica causalidad necesariamente. En palabras de Kendall y Stuart: \"Una relación estadística, por más fuerte y sugerente que sea, nunca podrá establecer una conexión causal: nuestras ideas de causalidad deben provenir de estadísticas externas y, en último término, de una u otra teoría\".", "title": "La regresión no implica causalidad", "eq": "¿Qué elementos adicionales, más allá de la evidencia estadística, se necesitan para establecer una relación causal entre variables?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La regresión establece dependencia ESTADÍSTICA, no causalidad. Para inferir causalidad se requieren: (1) teoría económica a priori, (2) sentido común sobre la dirección lógica de la relación, (3) diseño experimental o cuasi-experimental.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Correlación/dependencia ≠ causalidad. Ejemplo clásico: la correlación entre ventas de helados y ahogamientos es alta, pero ambas son causadas por el calor del verano (variable omitida), no una por la otra.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: Kendall y Stuart (1961) formulan esta advertencia fundamental: la causalidad debe provenir de la teoría, no de la estadística. Esto es un principio epistemológico central de la econometría.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Si la regresión no puede probar causalidad, ¿por qué es tan útil en economía? Porque permite cuantificar la magnitud y significancia de relaciones que la teoría económica ya ha postulado como causales.", "c": "7B5800", "b": true}]}, {"text": "El análisis de correlación se relaciona de manera estrecha con el de regresión, aunque conceptualmente los dos son muy diferentes. En el análisis de correlación, el objetivo principal es medir la fuerza o el grado de asociación lineal entre dos variables. El coeficiente de correlación, que veremos en detalle en el capítulo 3, mide esta fuerza de asociación (lineal): por ejemplo, si se desea encontrar la correlación (coeficiente) entre el hábito de fumar y el cáncer del pulmón; entre las calificaciones en exámenes de estadística y en exámenes de matemáticas; entre las calificaciones de bachillerato y de la universidad, y así sucesivamente. En el análisis de regresión, como ya mencionamos, no interesa ese tipo de medición. En cambio, se trata de estimar o predecir el valor promedio de una variable con base en los valores fijos de otras.", "title": "Diferencias entre análisis de correlación y regresión", "eq": "¿Por qué la correlación entre X e Y es simétrica pero la regresión de Y sobre X no es igual a la regresión de X sobre Y?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: CORRELACIÓN mide la fuerza de la asociación lineal (simétrica: r(X,Y) = r(Y,X)). REGRESIÓN estima la media condicional (asimétrica: Y|X ≠ X|Y). Son herramientas con propósitos distintos.", "c": "C00000", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: En la regresión hay asimetría: la variable dependiente (Y) es estocástica con distribución de probabilidad, mientras que las variables explicativas (X) se asumen con valores fijos en muestras repetidas.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: La correlación entre calificaciones de matemáticas y estadística es la misma sin importar cuál se considera 'dependiente'. Pero la regresión de calificaciones de estadística sobre calificaciones de matemáticas produce una ecuación diferente a la regresión inversa.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El coeficiente de correlación r y su relación con R² se formalizan en el Capítulo 3, donde se demuestra que r² = R² en el caso bivariado.", "c": "2D2D8F", "b": true}]}, {"text": "Antes de proceder al análisis formal de la teoría de regresión abordaremos brevemente la terminología y la notación. En las publicaciones especializadas, los términos variable dependiente y variable explicativa se definen de varias maneras. Si se estudia la dependencia de una variable respecto de una única variable explicativa, como el consumo que depende del ingreso real, dicho estudio se conoce como análisis de regresión simple, o con dos variables. Sin embargo, si se estudia la dependencia de una variable respecto de más de una variable explicativa, como el rendimiento de un cultivo, la lluvia, la temperatura, el Sol y los fertilizantes, se trata de un análisis de regresión múltiple. En otras palabras, en una regresión de dos variables sólo hay una variable explicativa, mientras que en la regresión múltiple hay más de una variable explicativa.", "title": "Terminología: regresión simple versus regresión múltiple", "eq": "¿Por qué se llama 'regresión con dos variables' si solo hay una variable explicativa?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Regresión SIMPLE (dos variables) = 1 variable dependiente + 1 variable explicativa. Regresión MÚLTIPLE = 1 variable dependiente + 2 o más variables explicativas. Se llama 'dos variables' porque el modelo contiene dos variables: Y y X.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: Sinónimos para variable dependiente: explicada, predicha, regresada, de respuesta, endógena, de resultado. Para variable explicativa: independiente, predictora, regresora, estímulo, exógena, covariante, de control.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: La letra Y denota la variable dependiente, X (X₁, X₂,...,Xₖ) las explicativas. Subíndice i = datos transversales, subíndice t = series de tiempo. N = observaciones en la población, n = en la muestra.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: La regresión múltiple se desarrolla formalmente en el Capítulo 7, extendiendo el método MCO al caso de múltiples regresoras.", "c": "2D2D8F", "b": true}]}, {"text": "Hay tres tipos de datos disponibles para el análisis empírico: series de tiempo, series transversales e información combinada (combinación de series de tiempo y transversales). Una serie de tiempo es un conjunto de observaciones sobre los valores de una variable en diferentes momentos. Tal información debe recopilarse en intervalos regulares, es decir, en forma diaria (precios de acciones, informes del tiempo, etc.), semanal (como cifras de oferta monetaria), mensual (tasa de desempleo, Índice de Precios al Consumidor [IPC], etc.), trimestral (como el PIB), anual (como los presupuestos del gobierno), quinquenal (como el censo de la industria manufacturera), o decenal (como los censos de población).", "title": "Tipos de datos: series de tiempo, transversales y combinados", "eq": "¿Qué problemas econométricos específicos surgen al usar cada tipo de datos?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Series de tiempo = observaciones de una variable a lo largo del tiempo (misma unidad, diferentes momentos). Datos transversales = observaciones de múltiples unidades en un mismo momento. Datos combinados = ambos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Las series de tiempo requieren el supuesto de ESTACIONARIEDAD (media y varianza constantes en el tiempo). Si la serie no es estacionaria, los resultados de regresión pueden ser espurios. Se desarrolla en el Capítulo 21.", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Los datos transversales enfrentan el problema de HETEROGENEIDAD: las unidades pueden ser muy diferentes en escala (ej: Alaska vs. Pensilvania en producción de huevo), lo cual requiere ajustes. Se aborda en el Capítulo 11.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Los datos en PANEL (mismo individuo observado en múltiples periodos) son un caso especial que combina ambas dimensiones y se estudia en el Capítulo 16.", "c": "2D2D8F", "b": true}]}, {"text": "Hay un tipo especial de datos combinados en el cual se estudia a través del tiempo la misma unidad transversal (por ejemplo, una familia o una empresa). Por ejemplo, el Departamento de Comercio de Estados Unidos realiza un censo de vivienda en intervalos periódicos. En cada encuesta periódica se entrevista a la misma unidad familiar (o a la gente que vive en la misma dirección) para averiguar si ha habido algún cambio en las condiciones de vivienda o financieras de esa unidad familiar desde la última encuesta. Los datos en panel que se obtienen de las entrevistas periódicas de la misma unidad familiar proporcionan información muy útil sobre la dinámica del comportamiento de las unidades familiares, como veremos en el capítulo 16.", "title": "Datos en panel: seguimiento longitudinal de unidades", "eq": "¿Qué ventaja tiene un panel balanceado sobre un panel desbalanceado para la estimación econométrica?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Datos en panel (longitudinales) = la misma unidad transversal (familia, empresa, país) observada en múltiples periodos. Combina la riqueza de los datos transversales con la dinámica temporal.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Panel BALANCEADO = todas las unidades tienen el mismo número de observaciones temporales. Panel DESBALANCEADO = algunas unidades tienen más observaciones que otras (por datos faltantes o entrada/salida de la muestra).", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Un estudio que sigue a 500 empresas durante 10 años para analizar cómo la inversión en I+D afecta la productividad. El panel permite controlar por características inobservables de cada empresa que no cambian en el tiempo (efectos fijos).", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Los modelos de regresión con datos en panel (efectos fijos, efectos aleatorios) se desarrollan formalmente en el Capítulo 16.", "c": "2D2D8F", "b": true}]}, {"text": "Si bien se dispone de numerosos datos para la investigación económica, su calidad no siempre es adecuada, y por múltiples razones. Como ya vimos, en su mayoría, los datos de las ciencias sociales son de naturaleza no experimental. Por consiguiente, es posible incurrir en errores de observación, sea por acción u omisión. Aun en datos reunidos experimentalmente surgen errores de medición debido a las aproximaciones o al redondeo. En encuestas por cuestionarios, el problema de la falta de respuesta puede ser grave; un investigador tiene suerte si obtiene una tasa de respuesta de 40%. El análisis basado en dicha tasa de respuesta parcial quizá no refleje de verdad el comportamiento del 60% que no respondió, y ocasione, por consiguiente, un sesgo de selectividad (muestral).", "title": "Problemas de calidad y precisión de los datos económicos", "eq": "¿Cómo afectan los errores de medición a la estimación de los coeficientes de regresión?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Los datos en ciencias sociales son mayoritariamente NO experimentales: el investigador no controla las variables explicativas. Esto dificulta establecer causalidad y puede introducir sesgos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: El sesgo de selectividad (muestral) ocurre cuando los individuos que responden encuestas difieren sistemáticamente de los que no responden. Si el 60% no responde, las conclusiones basadas en el 40% pueden no ser generalizables.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: 'El resultado de la investigación será tan bueno como lo sea la calidad de los datos'. Errores de medición, agregación excesiva y confidencialidad pueden comprometer seriamente los resultados econométricos.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Si la mayoría de los datos económicos tienen problemas de calidad, ¿deberíamos desconfiar de todos los resultados econométricos? No necesariamente, pero debemos reportar las limitaciones y evitar ser dogmáticos.", "c": "7B5800", "b": true}]}, {"text": "Las variables que a menudo encontrará se clasifican en cuatro categorías generales: escala de razón, escala de intervalo, escala ordinal y escala nominal. Es importante comprender cada una. Para la variable X en escala de razón, al tomar dos valores (X1 y X2), la razón X1/X2 y la distancia (X2 − X1) son cantidades con un significado. Asimismo, hay un ordenamiento natural de los valores a lo largo de la escala. Una variable en escala de intervalo satisface las dos últimas propiedades de la variable en escala de razón, pero no la primera. Una variable pertenece a la escala ordinal sólo si satisface la tercera propiedad de la escala de razón (es decir, el orden natural). Las variables en escala nominal simplemente denotan categorías. Como veremos, las técnicas econométricas adecuadas para las variables en escala de razón no resultarían pertinentes para las variables en escala nominal.", "title": "Escalas de medición: razón, intervalo, ordinal y nominal", "eq": "¿Qué técnica econométrica se usa cuando la variable dependiente está en escala nominal (por ejemplo, sí/no)?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Escala de RAZÓN: distancia y razón significativas + orden natural (ej: ingreso en dólares). Escala de INTERVALO: distancia significativa pero razón no (ej: temperatura Fahrenheit). Escala ORDINAL: solo el orden importa (ej: calificaciones A,B,C). Escala NOMINAL: solo categorías (ej: género).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: La escala de medición determina qué técnicas econométricas son apropiadas. Variables nominales como dependientes requieren modelos logit/probit (Capítulo 15), no MCO convencional.", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: El PIB en pesos es escala de razón (un PIB de 200 es el doble de 100). La temperatura corporal en °C es intervalo (37°C no es 'el doble de caliente' que 18.5°C). El nivel socioeconómico (alto/medio/bajo) es ordinal. La nacionalidad es nominal.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las variables cualitativas (nominales y ordinales) como regresoras se tratan en el Capítulo 9 mediante variables dicótomas (dummy).", "c": "2D2D8F", "b": true}]}], "retrieval": {"q": ["¿Qué es el análisis de regresión según su definición moderna y cuál es su objetivo principal?", "¿Cuál es la diferencia fundamental entre una relación estadística y una relación determinista?", "¿Por qué la regresión no implica causalidad? ¿Qué se necesita adicionalmente para inferir causalidad?", "¿Cuáles son los tres tipos principales de datos disponibles para el análisis empírico y qué problemas específicos presenta cada uno?"], "a": ["El análisis de regresión estudia la dependencia de una variable (dependiente) respecto de una o más variables (explicativas), con el objetivo de estimar o predecir la media o valor promedio poblacional de la variable dependiente dados los valores conocidos o fijos de las variables explicativas. A diferencia de la interpretación original de Galton (regresión a la media), la interpretación moderna se centra en la estimación de relaciones funcionales entre variables.", "En una relación estadística, las variables son aleatorias o estocásticas (tienen distribuciones de probabilidad), por lo que la predicción es inexacta y siempre hay variabilidad intrínseca. En una relación determinista (como las leyes de la física), las variables no son aleatorias y la relación es exacta dado que se conocen todos los factores. La econometría trabaja con relaciones estadísticas.", "La regresión solo establece dependencia estadística, no causalidad. Como señalan Kendall y Stuart, una relación estadística, por fuerte que sea, nunca puede establecer una conexión causal. Para inferir causalidad se necesitan: (1) una teoría económica que postule la dirección causal, (2) consideraciones a priori basadas en el sentido común, y (3) idealmente, diseños experimentales o cuasi-experimentales.", "Los tres tipos son: (1) Series de tiempo: observaciones de una variable en diferentes momentos, cuyo problema principal es la estacionariedad (media y varianza constantes). (2) Datos transversales: observaciones de múltiples unidades en un mismo momento, cuyo problema principal es la heterogeneidad entre unidades. (3) Datos combinados (y su caso especial, datos en panel): combinan ambas dimensiones, proporcionando información sobre la dinámica temporal de las unidades transversales."]}}, {"title": "CAPÍTULO 2: ANÁLISIS DE REGRESIÓN CON DOS VARIABLES: ALGUNAS IDEAS BÁSICAS", "paragraphs": [{"text": "En el capítulo 1 vimos el concepto de regresión en términos generales. En este capítulo lo abordamos más formalmente. De manera específica, este capítulo y los tres siguientes introducirán al lector a la teoría básica del análisis de regresión más sencillo posible, es decir, la regresión bivariable o con dos variables, en la cual la variable dependiente (la regresada) se relaciona con una sola variable explicativa (la regresora). Consideremos primero este caso no necesariamente por su adecuación práctica, sino porque presenta las ideas fundamentales del análisis de regresión de la manera más sencilla posible, y algunas de estas ideas pueden ilustrarse con diagramas bidimensionales. Además, como veremos, el análisis de regresión múltiple, más general, en el que la regresada se relaciona con más de una regresora, es, en muchos sentidos, una extensión lógica del caso de dos variables.", "title": "Justificación del modelo bivariado como punto de partida", "eq": "¿En qué sentido preciso la regresión múltiple es una 'extensión lógica' del caso de dos variables?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La regresión bivariable (dos variables) relaciona UNA variable dependiente (regresada) con UNA variable explicativa (regresora). Es el modelo más simple: Y = f(X) + error. Se estudia primero por razones pedagógicas.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Todos los conceptos del modelo bivariado (FRP, FRM, MCO, propiedades de estimadores) se extienden al caso múltiple. Dominar el caso simple es prerequisito para la regresión múltiple del Capítulo 7.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: Retoma la definición general de regresión de la sección 1.2 y la formaliza con notación matemática para el caso bivariado.", "c": "006B6B", "b": true}]}, {"text": "Como se señaló en la sección 1.2, el análisis de regresión se relaciona en gran medida con la estimación o predicción de la media (de la población) o valor promedio de la variable dependiente, con base en los valores conocidos o fijos de las variables explicativas. Para entender esto, consideremos los datos de la tabla 2.1. Estos datos se refieren a la población total de 60 familias de una comunidad hipotética, así como a su ingreso semanal (X) y su gasto de consumo semanal (Y), en dólares. Las 60 familias se dividen en 10 grupos de ingresos (de 80 dólares a 260); asimismo, aparecen los gastos semanales de cada familia de los diversos grupos. Por consiguiente, hay 10 valores fijos de X y los correspondientes valores Y para cada valor X; así, hay 10 subpoblaciones Y.", "title": "El ejemplo hipotético consumo-ingreso con 60 familias", "eq": "¿Por qué es pedagógicamente útil usar una POBLACIÓN completa (60 familias) en lugar de una muestra para introducir los conceptos de regresión?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El ejemplo usa la POBLACIÓN completa (no una muestra) para mostrar que para cada nivel de ingreso X existe una DISTRIBUCIÓN (subpoblación) de valores de consumo Y. Esto permite visualizar directamente las medias condicionales.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: Subpoblación de Y: para cada valor fijo de X (ej: ingreso = $140), existen múltiples valores observados de Y (consumo). La variabilidad dentro de cada subpoblación es la esencia de la naturaleza estadística de la regresión.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si tomas todas las familias que ganan $160/semana, no todas gastan lo mismo: algunas gastan $102, otras $107, $110, $116, $118, $125. El análisis de regresión resume esta variabilidad calculando la media condicional E(Y|X=160) = 113.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: En la sección 2.6 se introduce el problema REAL: solo tenemos una muestra, no la población. La FRM busca estimar la FRP a partir de datos muestrales.", "c": "2D2D8F", "b": true}]}, {"text": "Es importante distinguir entre los valores esperados condicionales y el valor esperado incondicional del consumo semanal, E(Y). Si sumamos los consumos semanales de las 60 familias que forman la población y dividimos este número entre 60, obtendremos la cantidad de 121.20 dólares ($7 272/60), que es el valor de la media incondicional, o esperada, del consumo semanal, E(Y); es incondicional porque, para obtener esta cifra, obviamos los niveles de ingreso de las diversas familias. Como es lógico, los diferentes valores esperados condicionales de Y varían respecto del valor esperado incondicional de Y, igual a 121.20 dólares. Cuando se plantea la pregunta \"¿cuál es el valor esperado del consumo semanal de una familia?\", la respuesta es 121.20 dólares (la media incondicional). Pero si se pregunta \"¿cuál es el valor esperado del consumo semanal de una familia cuyo ingreso mensual es de 140 dólares?\", la respuesta es 101 (la media condicional). Por consiguiente, conocer el nivel de ingreso permite predecir mejor el valor medio del consumo que si se ignora esa información. Tal vez sea ésta la esencia del análisis de regresión, como lo descubriremos a lo largo de este libro.", "title": "Media condicional versus media incondicional: la esencia de la regresión", "eq": "¿En qué sentido la media condicional es una 'mejor predicción' que la media incondicional?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Media INCONDICIONAL E(Y) = promedio de todos los Y sin considerar X (= $121.20). Media CONDICIONAL E(Y|Xᵢ) = promedio de Y para un valor específico de X (ej: E(Y|X=140) = $101). La regresión trabaja con medias condicionales.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: 'Conocer el nivel de ingreso permite predecir mejor el valor medio del consumo que si se ignora esa información'. Esta frase captura la ESENCIA del análisis de regresión: condicionar en X mejora la predicción de Y.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si alguien pregunta '¿cuánto gasta una familia típica?', sin más información respondemos $121.20 (media incondicional). Pero si sabemos que gana $260/semana, respondemos $173 (media condicional), una predicción mucho más precisa.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: La distinción condicional/incondicional es análoga a la diferencia entre probabilidad marginal P(Y) y probabilidad condicional P(Y|X) en teoría de probabilidad.", "c": "5B2C8C", "b": true}]}, {"text": "Los puntos oscuros dentro de círculos de la figura 2.1 muestran los valores medios condicionales de Y, graficados en función de los diferentes valores de X. Al unir esos valores obtenemos la línea de regresión poblacional (LRP), o, más general, la curva de regresión poblacional (CRP). Con palabras más sencillas, es la regresión de Y sobre X. El adjetivo \"poblacional\" se debe a que en este ejemplo trabajamos con la población total de 60 familias. Así, desde el punto de vista geométrico, una curva de regresión poblacional es tan sólo el lugar geométrico de las medias condicionales de la variable dependiente para los valores fijos de la(s) variable(s) explicativa(s). En palabras más simples, es la curva que conecta las medias de las subpoblaciones de Y que corresponden a los valores dados de la regresora X.", "title": "La línea de regresión poblacional como lugar geométrico de medias", "eq": "¿Por qué la LRP puede ser una curva y no necesariamente una recta?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La Línea (o Curva) de Regresión Poblacional (LRP/CRP) es el lugar geométrico de las medias condicionales E(Y|Xᵢ) para cada valor de X. Es la representación gráfica de la Función de Regresión Poblacional.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: La LRP es POBLACIONAL porque se construye con toda la población, no con una muestra. En la práctica, nunca se conoce la LRP verdadera; se estima mediante la Línea de Regresión Muestral (LRM).", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si graficamos el salario promedio por hora para cada año de escolaridad (6, 7, 8,...18 años), y conectamos esos promedios, obtenemos la CRP del salario sobre la escolaridad. La curva muestra cómo el salario esperado cambia con la educación.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: La formulación algebraica de esta curva como función E(Y|Xᵢ) = f(Xᵢ) se introduce inmediatamente en la sección 2.2 como Función de Regresión Poblacional (FRP).", "c": "2D2D8F", "b": true}]}, {"text": "De la anterior exposición, y en especial de las figuras 2.1 y 2.2, es claro que cada media condicional E(Y | Xi) es función de Xi, donde Xi es un valor dado de X. Simbólicamente,\nE(Y | Xi) = f(Xi)\ndonde f(Xi) denota alguna función de la variable explicativa X. En el ejemplo, E(Y | Xi) es una función lineal de Xi. La ecuación (2.2.1) se conoce como función de esperanza condicional (FEC), función de regresión poblacional (FRP) o regresión poblacional (RP), para abreviar. Dicha función sólo denota que el valor esperado de la distribución de Y dada Xi se relaciona funcionalmente con Xi. En otras palabras, dice cómo la media o respuesta promedio de Y varía con X.", "title": "Definición formal de la Función de Regresión Poblacional (FRP)", "eq": "¿Qué restricciones impone la suposición de que f(Xᵢ) es lineal y cuándo podría ser inapropiada?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La Función de Regresión Poblacional (FRP) es E(Y|Xᵢ) = f(Xᵢ). Describe cómo la media condicional de Y varía con X. También se llama Función de Esperanza Condicional (FEC). Es el objeto que la regresión busca estimar.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: En el caso lineal: E(Y|Xᵢ) = β₁ + β₂Xᵢ, donde β₁ = intercepto (valor esperado de Y cuando X=0) y β₂ = pendiente (cambio en la media de Y por unidad de cambio en X). Ambos son parámetros poblacionales desconocidos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Para los datos consumo-ingreso: E(Y|X) = 24.45 + 0.5091X. Si X=80, E(Y|80) = 24.45 + 0.5091(80) ≈ 65, que coincide con la media condicional observada. β₂ = 0.5091 es la propensión marginal a consumir.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: La FRP formaliza algebraicamente la recta de regresión que se introdujo gráficamente en la sección 1.2 del Capítulo 1.", "c": "006B6B", "b": true}]}, {"text": "Como este texto se relaciona sobre todo con modelos lineales, como la ecuación (2.2.2), es esencial entender a cabalidad el término lineal, pues se interpreta de dos formas.\nEl primer significado, y tal vez el más \"natural\", de linealidad es aquel en que la esperanza condicional de Y es una función lineal de Xi. Geométricamente, la curva de regresión en este caso es una recta. En esta interpretación, una función de regresión como E(Y | Xi) = β1 + β2X²i no es una función lineal porque la variable X aparece elevada a una potencia o índice de 2.\nLa segunda interpretación de linealidad se presenta cuando la esperanza condicional de Y, E(Y | Xi), es una función lineal de los parámetros, los β; puede ser o no lineal en la variable X. De acuerdo con esta interpretación, E(Y | Xi) = β1 + β2X²i es un modelo de regresión lineal (en el parámetro).\nDe las dos interpretaciones de linealidad, la linealidad en los parámetros es pertinente para el desarrollo de la teoría de regresión que presentaremos en breve. Por consiguiente, en adelante, el término regresión \"lineal\" siempre significará una regresión lineal en los parámetros.", "title": "Dos significados de 'lineal': en variables versus en parámetros", "eq": "¿Por qué es más importante la linealidad en los parámetros que la linealidad en las variables para la teoría de regresión?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Linealidad en VARIABLES: X aparece a la primera potencia (recta). Linealidad en PARÁMETROS: los β aparecen a la primera potencia. Un modelo puede ser no lineal en X pero lineal en β, y seguir siendo un 'modelo de regresión lineal'.", "c": "C00000", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: REGLA DEFINITIVA: 'Regresión lineal' = lineal en los PARÁMETROS β. El modelo E(Y|X) = β₁ + β₂X² ES lineal (en β) aunque X aparezca al cuadrado. El modelo E(Y|X) = β₁ + β₂²X NO es lineal porque β₂ aparece al cuadrado.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: El modelo cuadrático Y = β₁ + β₂X + β₃X² es un modelo de regresión LINEAL porque β₁, β₂ y β₃ aparecen linealmente. Se puede estimar con MCO convencional, simplemente definiendo X₁ = X y X₂ = X².", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Los modelos no lineales en los parámetros se tratan en el Capítulo 14. Las formas funcionales (semilog, doble-log) se ven en el Capítulo 6.", "c": "2D2D8F", "b": true}]}, {"text": "En la figura 2.1 es claro que, a medida que aumenta el ingreso familiar, el consumo familiar, en promedio, también aumenta. Pero, ¿qué sucede con el consumo de una familia en relación con su nivel de ingreso (fijo)? Es obvio, por la tabla 2.1 y la figura 2.1, que el consumo de una familia en particular no necesariamente aumenta a medida que lo hace el nivel de ingreso. Por ejemplo, en la tabla 2.1 se observa que en el nivel de ingreso de 100 dólares existe una familia cuyo consumo, de 65, es menor que el consumo de dos familias cuyo ingreso semanal es sólo de 80 dólares. Sin embargo, hay que advertir que el consumo promedio de las familias con ingreso semanal de 100 es mayor que el consumo promedio de las familias con un ingreso semanal de 80 dólares (77 y 65).\nEntonces, ¿qué se puede decir sobre la relación entre el consumo de una familia y un nivel determinado de ingresos? En la figura 2.1 se ve que, con el nivel de ingresos de Xi, el consumo de una familia en particular se agrupa alrededor del consumo promedio de todas las familias en ese nivel de Xi, es decir, alrededor de su esperanza condicional. Por consiguiente, expresamos la desviación de un Yi en particular alrededor de su valor esperado de la manera siguiente:\nui = Yi − E(Y | Xi)\no\nYi = E(Y | Xi) + ui\ndonde la desviación ui es una variable aleatoria no observable que adopta valores positivos o negativos. Técnicamente, ui se conoce como perturbación estocástica o término de error estocástico.", "title": "El término de perturbación estocástica uᵢ y la FRP estocástica", "eq": "¿Qué representan exactamente los valores positivos y negativos de uᵢ en el contexto del ejemplo consumo-ingreso?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La perturbación estocástica uᵢ captura la desviación de un valor individual Yᵢ respecto de la media condicional E(Y|Xᵢ). La ecuación fundamental es: Yᵢ = E(Y|Xᵢ) + uᵢ, donde uᵢ es aleatorio, no observable, y puede ser positivo o negativo.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La FRP estocástica en forma lineal es: Yᵢ = β₁ + β₂Xᵢ + uᵢ. El consumo individual tiene dos componentes: (1) E(Y|Xᵢ) = β₁ + β₂Xᵢ (componente sistemático/determinista) y (2) uᵢ (componente aleatorio/no sistemático).", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El supuesto fundamental E(uᵢ|Xᵢ) = 0 es equivalente a decir que la línea de regresión pasa por las medias condicionales de Y. Sin este supuesto, la FRP determinista y estocástica no serían equivalentes.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Una familia con ingreso X=80 y consumo Y=75 tiene uᵢ = 75 - 65 = +10 (gasta más que el promedio de su grupo). Otra con Y=55 tiene uᵢ = 55 - 65 = -10 (gasta menos). En promedio, las desviaciones se cancelan: E(uᵢ|X=80) = 0.", "c": "1A5C38", "b": true}]}, {"text": "Como anotamos en la sección 2.4, el término de perturbación ui es un sustituto de todas las variables que se omiten en el modelo, pero que, en conjunto, afectan a Y. La pregunta obvia es: ¿por qué no se introducen explícitamente estas variables en el modelo? O de otra forma, ¿por qué no se crea un modelo de regresión múltiple con tantas variables como sea posible? Las razones son muchas.\n1. Vaguedad de la teoría: De existir una teoría que determine el comportamiento de Y, podría estar incompleta, y con frecuencia lo está.\n2. Falta de disponibilidad de datos: Aunque se conozcan algunas variables excluidas y se considerara por tanto una regresión múltiple en lugar de una simple, tal vez no se cuente con información cuantitativa sobre esas variables.\n3. Variables centrales y variables periféricas: Es muy posible que la influencia conjunta de algunas variables sea muy pequeña, o a lo mejor no sistemática ni aleatoria.\n4. Aleatoriedad intrínseca en el comportamiento humano: Aunque se logre introducir en el modelo todas las variables pertinentes, es posible que se presente alguna aleatoriedad \"intrínseca\" en Y que no se explique.\n5. Variables representantes (proxy) inadecuadas: En la práctica, los datos pueden estar plagados de errores de medición.\n6. Principio de parsimonia: De acuerdo con el principio de la navaja de Occam, conviene mantener el modelo de regresión lo más sencillo posible.\n7. Forma funcional incorrecta: Con frecuencia no se conoce la forma de la relación funcional entre la variable regresada y las regresoras.", "title": "Siete razones para la existencia del término de perturbación", "eq": "¿Cuál de las siete razones es la más problemática para la econometría y por qué?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Las 7 razones del término uᵢ: (1) Teoría incompleta, (2) Datos no disponibles, (3) Variables periféricas, (4) Aleatoriedad intrínseca humana, (5) Errores de medición (proxies), (6) Parsimonia (navaja de Occam), (7) Forma funcional incorrecta.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El principio de parsimonia (navaja de Occam) establece que se debe mantener el modelo lo más sencillo posible hasta que se demuestre inadecuado. No se deben agregar variables innecesarias, pero tampoco excluir variables relevantes.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: Milton Friedman y su teoría del ingreso permanente: el consumo depende del ingreso permanente (Yp), pero solo observamos el ingreso actual (Y). La diferencia entre Y e Yp es un error de medición que se absorbe en uᵢ.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Para modelar el rendimiento académico (Y), podrías incluir horas de estudio (X₁), asistencia (X₂), pero omitir motivación intrínseca, calidad del sueño, y estado emocional. Estas variables omitidas se capturan colectivamente en uᵢ.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Si uᵢ contiene variables omitidas correlacionadas con X, el estimador MCO será sesgado (sesgo de variable omitida). Este problema fundamental se aborda en capítulos posteriores.", "c": "7B5800", "b": true}]}, {"text": "Hasta el momento, nos hemos limitado a la población de valores Y que corresponden a valores fijos de X. Con toda deliberación evitamos consideraciones muestrales (observe que los datos de la tabla 2.1 representan la población, no una muestra). No obstante, es momento de enfrentar los problemas muestrales, porque en la práctica lo que se tiene al alcance no es más que una muestra de valores de Y que corresponden a algunos valores fijos de X. Por tanto, la labor ahora es estimar la FRP con base en información muestral.", "title": "De la población a la muestra: necesidad de la FRM", "eq": "¿Por qué diferentes muestras de la misma población generan diferentes líneas de regresión muestral?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: En la práctica NUNCA se conoce la FRP (parámetros poblacionales β₁ y β₂). Solo se dispone de una muestra. La tarea central de la econometría es estimar la FRP a partir de la Función de Regresión Muestral (FRM).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: FRP: Yᵢ = β₁ + β₂Xᵢ + uᵢ (parámetros poblacionales, verdaderos pero desconocidos). FRM: Yᵢ = β̂₁ + β̂₂Xᵢ + ûᵢ (estimadores muestrales, conocidos pero aproximados). El 'sombrero' (^) indica estimador.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Debido a las fluctuaciones muestrales, la FRM es solo una aproximación de la FRP. Diferentes muestras producen diferentes FRM, y ninguna coincidirá exactamente con la FRP verdadera.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El método para construir la FRM que mejor aproxime la FRP (Mínimos Cuadrados Ordinarios, MCO) se desarrolla en el Capítulo 3.", "c": "2D2D8F", "b": true}]}, {"text": "Ahora, igual que la FRP en la cual se basa la línea de regresión poblacional, se desarrolla el concepto de función de regresión muestral (FRM) para representar la línea de regresión muestral. La contraparte muestral de la ecuación (2.2.2) puede escribirse como\nŶi = β̂1 + β̂2Xi\ndonde Ŷ se lee \"Y sombrero\" o \"Y gorra\"\nŶi = estimador de E(Y | Xi)\nβ̂1 = estimador de β1\nβ̂2 = estimador de β2\nAdvierta que un estimador, conocido también como estadístico (muestral), no es más que una regla, fórmula o método para estimar el parámetro poblacional a partir de la información suministrada por la muestra disponible. Un valor numérico particular obtenido por el estimador en un análisis se conoce como estimación. Cabe señalar que un estimador es aleatorio, pero una estimación no.", "title": "Definición formal de la Función de Regresión Muestral (FRM)", "eq": "¿Por qué un estimador es aleatorio pero una estimación no lo es?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La FRM es Ŷᵢ = β̂₁ + β̂₂Xᵢ, donde β̂₁ y β̂₂ son ESTIMADORES de los parámetros poblacionales β₁ y β₂. La notación con sombrero (^) siempre indica un valor estimado, no el verdadero.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: ESTIMADOR = regla o fórmula (variable aleatoria, porque depende de la muestra que se obtenga). ESTIMACIÓN = valor numérico concreto obtenido al aplicar el estimador a una muestra específica (no es aleatorio). β̂₂ como fórmula es estimador; β̂₂ = 0.5091 es estimación.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: La FRM estocástica es Yᵢ = β̂₁ + β̂₂Xᵢ + ûᵢ, donde ûᵢ es el RESIDUAL (muestral), análogo a uᵢ (perturbación poblacional). El residual ûᵢ es observable; la perturbación uᵢ no lo es.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las propiedades deseables de los estimadores (insesgamiento, eficiencia, consistencia) se desarrollan en los Capítulos 3 y 4 bajo los supuestos del modelo clásico de regresión lineal.", "c": "2D2D8F", "b": true}]}, {"text": "Así, para resumir, concluimos que el objetivo principal del análisis de regresión es estimar la FRP\nYi = β1 + β2Xi + ui\ncon base en la FRM\nYi = β̂1 + β̂2Xi + ûi\nporque son más frecuentes los casos en que el análisis se basa en una sola muestra tomada de una población. Pero, debido a fluctuaciones muestrales, la estimación de la FRP basada en la FRM es, en el mejor de los casos, una aproximación. La pregunta crítica es ahora: como la FRM es apenas una aproximación de la FRP, ¿se puede diseñar una regla o método que \"acerque\" esta aproximación lo más posible? En otras palabras, ¿cómo se debe construir la FRM para que β̂1 y β̂2 estén tan \"cerca\" de los verdaderos β1 y β2 como sea posible, aunque nunca se lleguen a conocer los verdaderos β1 y β2?\nLa respuesta ocupará gran parte del capítulo 3.", "title": "El problema central: estimar la FRP a partir de la FRM", "eq": "¿Qué criterio se usa para definir 'lo más cerca posible' cuando comparamos β̂ con β?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El OBJETIVO CENTRAL de la econometría: estimar la FRP (Yᵢ = β₁ + β₂Xᵢ + uᵢ) a partir de la FRM (Yᵢ = β̂₁ + β̂₂Xᵢ + ûᵢ). Los parámetros verdaderos β nunca se conocen; solo se estiman mediante β̂.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Las 'fluctuaciones muestrales' significan que β̂ varía de muestra a muestra. La pregunta central es: ¿cómo elegir un método de estimación que minimice la distancia entre β̂ y β? El Capítulo 3 responde: Mínimos Cuadrados Ordinarios (MCO).", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: Este problema es análogo a la inferencia estadística general: usar un estadístico muestral (x̄) para estimar un parámetro poblacional (μ). La regresión es un caso especial donde se estiman β₁ y β₂ en lugar de μ.", "c": "5B2C8C", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El método MCO del Capítulo 3 resuelve este problema minimizando la suma de residuales al cuadrado Σûᵢ², produciendo estimadores con propiedades óptimas bajo los supuestos clásicos.", "c": "2D2D8F", "b": true}]}, {"text": "La tabla 2.6 proporciona datos sobre el nivel de estudios (medido en años de escolaridad), el salario promedio por hora devengado por las personas por nivel de escolaridad y el número de personas en un nivel de estudios. Ernst Berndt obtuvo originalmente los datos de la tabla de la encuesta de población de mayo de 1985.\nAl trazar el salario promedio (condicional) en función del grado de escolaridad, se obtiene la gráfica de la figura 2.6. La curva de regresión de la gráfica muestra la variación de los salarios promedio de acuerdo con el grado de escolaridad; por lo general, aquéllos se incrementan a la par que el grado de escolaridad, conclusión que no debe causar sorpresa.", "title": "Ejemplo empírico: salario promedio según años de escolaridad", "eq": "¿La relación positiva entre escolaridad y salario refleja causalidad o simplemente correlación?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Este ejemplo ilustra la FRP empírica: el salario promedio por hora (media condicional) se grafica contra años de escolaridad. La curva resultante es la estimación de E(Salario | Escolaridad = X).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Con 6 años de escolaridad, el salario promedio es $4.46/hora; con 18 años, es $13.53/hora. Cada año adicional de educación se asocia con un incremento en el salario promedio, aunque la relación no es perfectamente lineal.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: ¿El salario más alto se debe a la escolaridad per se, o a habilidades no observadas (inteligencia, disciplina) que correlacionan con la escolaridad? Este es el problema de variables omitidas que afecta la interpretación causal.", "c": "7B5800", "b": true}]}], "retrieval": {"q": ["¿Qué es la Función de Regresión Poblacional (FRP) y cómo se expresa en su forma lineal?", "¿Cuál es la diferencia entre la FRP y la FRM, y por qué es necesaria la FRM?", "¿Qué representa el término de perturbación estocástica uᵢ y cuáles son las principales razones de su existencia?", "¿Qué significa que un modelo sea 'lineal en los parámetros' y por qué esta definición es la relevante en econometría?"], "a": ["La FRP es E(Y|Xᵢ) = f(Xᵢ), que describe cómo la media condicional de Y varía con X. En su forma lineal: E(Y|Xᵢ) = β₁ + β₂Xᵢ, donde β₁ es el intercepto y β₂ la pendiente. Geométricamente, es el lugar de las medias condicionales de Y para valores fijos de X. También se conoce como Función de Esperanza Condicional (FEC).", "La FRP (Yᵢ = β₁ + β₂Xᵢ + uᵢ) contiene los parámetros POBLACIONALES verdaderos pero desconocidos. La FRM (Yᵢ = β̂₁ + β̂₂Xᵢ + ûᵢ) contiene ESTIMADORES muestrales de esos parámetros. La FRM es necesaria porque en la práctica nunca tenemos acceso a toda la población, solo a una muestra. Diferentes muestras producen diferentes FRM, y la FRM es solo una aproximación de la FRP verdadera.", "El término uᵢ captura la desviación de un valor individual Yᵢ respecto de su media condicional E(Y|Xᵢ). Existe por 7 razones: (1) teoría incompleta, (2) datos no disponibles, (3) variables periféricas de efecto menor, (4) aleatoriedad intrínseca del comportamiento humano, (5) errores de medición en variables proxy, (6) principio de parsimonia (navaja de Occam), y (7) posible forma funcional incorrecta. El supuesto clave es E(uᵢ|Xᵢ) = 0.", "Un modelo es 'lineal en los parámetros' cuando los coeficientes β aparecen elevados solo a la primera potencia y no están multiplicados entre sí. El modelo E(Y|X) = β₁ + β₂X² ES lineal (en β) aunque X esté al cuadrado, porque β₁ y β₂ son lineales. El modelo E(Y|X) = β₁ + β₂²X NO es lineal porque β₂ está al cuadrado. Esta definición es la relevante porque determina si se puede usar el método MCO para la estimación."]}}, {"title": "CAPÍTULO 3: MODELO DE REGRESIÓN CON DOS VARIABLES: PROBLEMA DE ESTIMACIÓN", "paragraphs": [{"text": "Como explicamos en el capítulo 2, la primera tarea consiste en estimar la función de regresión poblacional (FRP) con base en la función de regresión muestral (FRM) en la forma más precisa posible. En el apéndice A se analizan dos métodos de estimación frecuentes: 1) mínimos cuadrados ordinarios (MCO) y 2) máxima verosimilitud (MV). El método de MCO es el más común en el análisis de regresión, sobre todo por ser mucho más intuitivo y matemáticamente más sencillo que el método de máxima verosimilitud. Además, como veremos más adelante, en el contexto de la regresión lineal, por lo general los dos métodos proporcionan resultados similares.", "title": "Introducción a los métodos de estimación MCO y MV", "eq": "¿Por qué el método de MCO es más popular que el de máxima verosimilitud en el análisis de regresión?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: MCO (Mínimos Cuadrados Ordinarios) es un método de estimación que minimiza la suma de los residuos al cuadrado para obtener los estimadores de los parámetros de regresión.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: MV (Máxima Verosimilitud) es un método alternativo que maximiza la probabilidad de observar los datos muestrales dados los parámetros desconocidos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: FRP (función poblacional) vs. FRM (función muestral): la FRP es el modelo teórico verdadero; la FRM es su estimación a partir de datos observados.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: Estos conceptos de FRP y FRM fueron introducidos en el Capítulo 2, ecuación (2.4.2).", "c": "006B6B", "b": true}]}, {"text": "El método de mínimos cuadrados ordinarios se atribuye a Carl Friedrich Gauss, matemático alemán. A partir de ciertos supuestos (estudiados en la sección 3.2), el método de mínimos cuadrados presenta propiedades estadísticas muy atractivas que lo han convertido en uno de los más eficaces y populares del análisis de regresión. Para entenderlo, primero explicaremos el principio de los mínimos cuadrados.", "title": "Origen histórico y fundamento del método MCO", "eq": "¿Qué propiedades estadísticas hacen que MCO sea tan popular en econometría?", "anns": [{"t": "◆◆◆ CRÍTICO:\nAUTOR / TEORÍA: Carl Friedrich Gauss (1777-1855) desarrolló el método de mínimos cuadrados en 1821, estableciendo el fundamento matemático de la estimación por regresión.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Imagine que quiere trazar la mejor línea recta a través de puntos dispersos en un gráfico de dispersión. MCO encuentra esa línea minimizando las distancias verticales al cuadrado entre cada punto y la línea.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las propiedades estadísticas de MCO se formalizan en el teorema de Gauss-Markov (sección 3.4).", "c": "2D2D8F", "b": true}]}, {"text": "Ahora, dados n pares de observaciones de Y y X, nos interesa determinar la FRM de manera que quede lo más cerca posible de la Y observada. Con este fin, se adopta el siguiente criterio: seleccionar la FRM de modo que la suma de los residuos ûi (Yi −Ŷi) sea la menor posible. Este criterio, aunque es intuitivamente atractivo, no es muy bueno, como se ve en el diagrama de dispersión hipotético de la figura 3.1.", "title": "Limitaciones del criterio de suma simple de residuos", "eq": "¿Por qué minimizar la suma simple de residuos no es un buen criterio de estimación?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La suma algebraica de residuos puede ser cero aun cuando los residuos individuales sean muy grandes, porque los positivos cancelan a los negativos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si los residuos son +10, −2, +2, −10, su suma es cero a pesar de que dos observaciones están muy lejos de la línea de regresión.", "c": "1A5C38", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Criterio de Σûi (suma simple, defectuoso) vs. Σû²i (suma de cuadrados, MCO): al elevar al cuadrado se penalizan más los residuos grandes y se evita la cancelación.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: ¿Qué pasaría si usáramos el valor absoluto de los residuos en lugar de elevarlos al cuadrado? Ese método existe y se llama regresión por mínimos absolutos.", "c": "7B5800", "b": true}]}, {"text": "Al resolver las ecuaciones normales al mismo tiempo, obtenemos β̂₂ = Σxiyi / Σx²i donde X̄ y Ȳ son las medias muestrales de X y Y, y donde se definen xi = (Xi − X̄) y yi = (Yi − Ȳ). De aquí en adelante adoptaremos la convención de utilizar letras minúsculas para representar desviaciones respecto de los valores medios. β̂₁ = Ȳ − β̂₂X̄", "title": "Fórmulas de los estimadores MCO de pendiente e intercepto", "eq": "¿Cómo se derivan las fórmulas de los estimadores de MCO a partir de las ecuaciones normales?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: β̂₂ = Σxiyi / Σx²i es el estimador MCO de la pendiente: mide el cambio promedio en Y por cada unidad de cambio en X.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: β̂₁ = Ȳ − β̂₂X̄ es el estimador del intercepto. Implica que la línea de regresión siempre pasa por el punto (X̄, Ȳ).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: Las ecuaciones normales (3.1.4) y (3.1.5) son las condiciones de primer orden obtenidas al derivar Σû²i respecto de β̂₁ y β̂₂ e igualar a cero.", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si en una muestra X̄=12, Ȳ=8.67, y β̂₂=0.724, entonces β̂₁ = 8.67 − 0.724(12) = −0.014. El intercepto negativo es un artefacto matemático sin interpretación económica.", "c": "1A5C38", "b": true}]}, {"text": "Los estimadores obtenidos antes se conocen como estimadores de mínimos cuadrados, pues se derivan del principio de mínimos cuadrados. Observe las siguientes propiedades numéricas de los estimadores obtenidos con el método de MCO: \"Propiedades numéricas son las que se mantienen como consecuencia del uso de mínimos cuadrados ordinarios, sin considerar la forma como se generaron los datos\". En breve consideraremos también las propiedades estadísticas de los estimadores MCO, es decir, propiedades \"que se mantienen sólo con ciertos supuestos sobre la forma como se generaron los datos\".", "title": "Propiedades numéricas vs. estadísticas de los estimadores MCO", "eq": "¿Cuál es la diferencia fundamental entre propiedades numéricas y propiedades estadísticas de los estimadores?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Propiedades numéricas (siempre se cumplen con MCO, sin importar supuestos) vs. propiedades estadísticas (requieren que se cumplan los supuestos del MCRL).", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: Propiedades numéricas incluyen: Σûi = 0, ΣûiXi = 0, la línea pasa por (X̄,Ȳ), Ȳ̂ = Ȳ.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las propiedades estadísticas (MELI) se estudian en la sección 3.4 con el teorema de Gauss-Markov.", "c": "2D2D8F", "b": true}]}, {"text": "Modelo de regresión lineal: El modelo de regresión es lineal en los parámetros, aunque puede o no ser lineal en las variables. Es decir, el modelo de regresión como se muestra en la ecuación (2.4.2) Yi = β1 + β2Xi + ui. Como analizaremos en el capítulo 7, este modelo puede extenderse para incluir más variables explicativas.", "title": "Supuesto 1 del MCRL: linealidad en los parámetros", "eq": "¿Por qué es importante que el modelo sea lineal en los parámetros y no necesariamente en las variables?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Linealidad en parámetros significa que β₁ y β₂ aparecen con potencia 1. Las variables X e Y pueden transformarse (logaritmo, cuadrado, etc.) sin violar este supuesto.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: El modelo ln(Yi) = β₁ + β₂ln(Xi) + ui es lineal en parámetros (MCO aplica), aunque no es lineal en las variables originales X e Y.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Los modelos no lineales en los parámetros se estudian en el Capítulo 14.", "c": "2D2D8F", "b": true}]}, {"text": "Valores fijos de X, o valores de X independientes del término de error: Los valores que toma la regresora X pueden considerarse fijos en muestras repetidas (el caso de la regresora fija), o haber sido muestreados junto con la variable dependiente Y (el caso de la regresora estocástica). En el segundo caso se supone que la(s) variable(s) X y el término de error son independientes, esto es, cov(Xi, ui) = 0.", "title": "Supuesto 2 del MCRL: regresora fija o independiente del error", "eq": "¿Qué implicaciones tiene para la estimación MCO que la variable X sea estocástica en lugar de fija?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: El análisis de regresión es condicional: se estima E(Y|X), la esperanza de Y dados valores específicos de X. Por eso MCO trata X como fija.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Regresora fija (MCRL clásico) vs. regresora estocástica (MNRL, modelo neoclásico): en ciencias sociales X suele ser aleatoria, pero los resultados de MCO se mantienen si cov(Xi, ui)=0.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Un agricultor que aplica cantidades fijas de fertilizante (X=10, 20, 30 kg) a parcelas y mide el rendimiento (Y) tiene una regresora fija. En una encuesta de hogares donde ingreso y consumo se observan juntos, X es estocástica.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El caso de regresoras estocásticas se analiza en detalle en el Capítulo 13.", "c": "2D2D8F", "b": true}]}, {"text": "El valor medio de la perturbación ui es igual a cero: Dado el valor de Xi, la media o el valor esperado del término de perturbación aleatoria ui es cero. Simbólicamente, tenemos que E(ui|Xi) = 0. O, si X no es estocástica, E(ui) = 0.", "title": "Supuesto 3 del MCRL: media condicional cero del error", "eq": "¿Qué implicaciones prácticas tiene que E(ui|Xi) = 0 para la correcta especificación del modelo?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: E(ui|Xi) = 0 significa que los factores omitidos (contenidos en u) no afectan sistemáticamente a Y. Los efectos positivos y negativos se cancelan en promedio.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nIMPLICACIÓN: Si E(ui|Xi) ≠ 0, hay sesgo de especificación: el modelo omite variables relevantes o usa una forma funcional incorrecta, produciendo estimadores sesgados.", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: E(ui|Xi) = 0 implica que E(Yi|Xi) = β₁ + β₂Xi. Los dos supuestos son equivalentes: si la perturbación tiene media cero, la FRP representa correctamente la media condicional de Y.", "c": "5B2C8C", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: Este supuesto formaliza la idea del Capítulo 2 (ecuación 2.4.5) de que ui captura influencias aleatorias no sistemáticas.", "c": "006B6B", "b": true}]}, {"text": "Homoscedasticidad o varianza constante de ui: La varianza del término de error, o de perturbación, es la misma sin importar el valor de X. Simbólicamente, tenemos que var(ui) = E(u²i|Xi) = σ². La ecuación (3.2.2) establece que la varianza de ui para cada Xi (es decir, la varianza condicional de ui) es algún número positivo constante igual a σ². Técnicamente, la ecuación (3.2.2) representa el supuesto de homoscedasticidad, o igual (homo) dispersión (cedasticidad), o igual varianza.", "title": "Supuesto 4 del MCRL: homoscedasticidad", "eq": "¿Cómo afecta la heteroscedasticidad a la eficiencia de los estimadores MCO?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Homoscedasticidad: var(ui|Xi) = σ² (constante). Todas las poblaciones de Y correspondientes a diferentes valores de X tienen la misma varianza.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Homoscedasticidad (varianza constante σ²) vs. heteroscedasticidad (varianza variable σ²i). Con heteroscedasticidad, MCO sigue siendo insesgado pero ya no es eficiente.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: En datos de consumo vs. ingreso, familias de alto ingreso muestran mayor variabilidad en consumo que familias pobres. Esto viola homoscedasticidad: var(u) crece con el ingreso.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El problema de heteroscedasticidad se trata a fondo en el Capítulo 11.", "c": "2D2D8F", "b": true}]}, {"text": "No hay autocorrelación entre las perturbaciones: Dados dos valores cualesquiera de X, Xi y Xj (i ≠ j), la correlación entre dos ui y uj cualesquiera (i ≠ j) es cero. En pocas palabras, estas observaciones se muestrean de manera independiente. Simbólicamente, cov(ui, uj|Xi, Xj) = 0. En palabras, (3.2.5) postula que las perturbaciones ui y uj no están correlacionadas. Técnicamente, éste es el supuesto de no correlación serial, o no autocorrelación.", "title": "Supuesto 5 del MCRL: no autocorrelación de perturbaciones", "eq": "¿En qué tipo de datos es más probable encontrar autocorrelación y por qué?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: No autocorrelación: cov(ui, uj) = 0 para i ≠ j. Las perturbaciones de diferentes observaciones no están correlacionadas entre sí.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Correlación serial positiva (a una u positiva sigue otra positiva) vs. negativa (a una positiva sigue una negativa) vs. cero correlación (sin patrón).", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: En series de tiempo (PIB trimestral, inflación mensual) la autocorrelación es común: la economía de un trimestre está influida por el anterior. En datos transversales de muestra aleatoria, es menos probable.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: La autocorrelación y sus consecuencias se estudian en detalle en el Capítulo 12.", "c": "2D2D8F", "b": true}]}, {"text": "El número de observaciones n debe ser mayor que el número de parámetros por estimar: Sucesivamente, el número de observaciones n debe ser mayor que el número de variables explicativas. La naturaleza de las variables X: No todos los valores X en una muestra determinada deben ser iguales. Técnicamente, var(X) debe ser un número positivo. Además, no puede haber valores atípicos de la variable X, es decir, valores muy grandes en relación con el resto de las observaciones.", "title": "Supuestos 6 y 7 del MCRL: tamaño muestral y variabilidad de X", "eq": "¿Por qué no se puede estimar una regresión con más parámetros que observaciones?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Supuesto 6: n > k (observaciones > parámetros). Con n=1 y dos parámetros β₁, β₂, el sistema es indeterminado: infinitas líneas pasan por un solo punto.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Supuesto 7: var(X) > 0. Si todos los Xi son iguales, Xi = X̄ y Σx²i = 0, lo que hace imposible calcular β̂₂ = Σxiyi/Σx²i (división por cero).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si estudiamos el efecto de la educación en el salario pero todos los individuos de la muestra tienen exactamente 12 años de escolaridad, no hay variación en X y no podemos estimar el efecto.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nIMPLICACIÓN: Los valores atípicos (outliers) en X pueden dominar la regresión. Si un valor de X es 20 veces el promedio, la línea estimada cambia drásticamente al incluirlo o excluirlo.", "c": "C55A11", "b": true}]}, {"text": "De las ecuaciones (3.1.6) y (3.1.7) es evidente que las estimaciones de mínimos cuadrados son función de los datos muestrales. Pero, como es probable que los datos cambien entre una muestra y otra, los valores estimados cambiarán ipso facto. Por consiguiente, se requiere alguna medida de \"confiabilidad\" o precisión de los estimadores β̂₁ y β̂₂. En estadística, la precisión de un valor estimado se mide por su error estándar (ee).", "title": "Errores estándar como medida de precisión de los estimadores", "eq": "¿Cómo se interpreta un error estándar grande en el contexto de la confiabilidad de un estimador?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: var(β̂₂) = σ²/Σx²i. La varianza del estimador de pendiente es directamente proporcional a σ² (varianza del error) e inversamente proporcional a la variación en X.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: σ̂² = Σû²i/(n−2) es el estimador insesgado de σ². Se divide por (n−2) porque se pierden 2 grados de libertad al estimar β̂₁ y β̂₂.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Para estimar β₂ con mayor precisión: (a) aumentar el tamaño muestral n, y/o (b) asegurar que haya suficiente variabilidad en los valores de X.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Los errores estándar son fundamentales para construir intervalos de confianza y pruebas de hipótesis (Capítulo 5).", "c": "2D2D8F", "b": true}]}, {"text": "Dados los supuestos del modelo clásico de regresión lineal, los estimadores de mínimos cuadrados, dentro de la clase de estimadores lineales insesgados, tienen varianza mínima, es decir, son MELI. Como ya mencionamos, dados los supuestos del modelo clásico de regresión lineal, las estimaciones de mínimos cuadrados poseen algunas propiedades ideales u óptimas, las cuales están contenidas en el famoso teorema de Gauss-Markov. Para entender este teorema necesitamos considerar la propiedad del mejor estimador lineal insesgado.", "title": "Teorema de Gauss-Markov: MCO produce estimadores MELI", "eq": "¿Qué sucede con la propiedad MELI si se viola alguno de los supuestos del MCRL?", "anns": [{"t": "◆◆◆ CRÍTICO:\nAUTOR / TEORÍA: Teorema de Gauss-Markov: bajo los supuestos del MCRL, los estimadores MCO son MELI (Mejor Estimador Lineal Insesgado). Gauss desarrolló MCO en 1821; Markov probó la varianza mínima en 1900.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: MELI descompuesto: (1) Lineal = función lineal de Y; (2) Insesgado = E(β̂₂) = β₂; (3) Mejor = varianza mínima dentro de la clase de estimadores lineales insesgados.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: El teorema NO requiere supuesto de normalidad de las perturbaciones. Solo requiere los supuestos del MCRL (supuestos 1-7).", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: MELI garantiza varianza mínima solo entre estimadores lineales insesgados. Podría existir un estimador no lineal con varianza aún menor (esto se resuelve en el Cap. 4 con normalidad).", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Si un investigador viola el supuesto de homoscedasticidad, ¿MCO sigue siendo insesgado? Sí, pero pierde eficiencia: ya no tiene varianza mínima.", "c": "7B5800", "b": true}]}, {"text": "El coeficiente de determinación r² (caso de dos variables) o R² (regresión múltiple) es una medida comprendida que dice cuán bien se ajusta la línea de regresión muestral a los datos. SCT = SCE + SCR muestra que la variación total en los valores Y observados alrededor del valor de su media puede dividirse en dos partes, una atribuible a la línea de regresión y la otra a fuerzas aleatorias, pues no todas las observaciones Y caen sobre la línea ajustada.", "title": "Coeficiente de determinación r² y descomposición de variación", "eq": "¿Por qué un r² alto no garantiza necesariamente que el modelo de regresión sea bueno?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: r² = SCE/SCT = 1 − SCR/SCT. Mide la proporción de la variación total de Y explicada por la regresión. Rango: 0 ≤ r² ≤ 1.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: SCT = SCE + SCR: Suma de Cuadrados Total = Suma de Cuadrados Explicada + Suma de Cuadrados de Residuos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Variación (Σ desviaciones²) vs. Varianza (variación/grados de libertad). SCT es variación; s²y = SCT/(n−1) es varianza.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: En la relación consumo-PIB de EE.UU. (1960-2005), r² = 0.9983: el PIB explica 99.83% de la variación en consumo. En datos transversales de India, r² = 0.37: mucha más variación individual no explicada.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Un r² de 0.99 en series de tiempo puede ser engañoso si ambas variables tienen tendencia creciente (regresión espuria). El r² alto puede deberse a la tendencia, no a una relación causal real.", "c": "7B5800", "b": true}]}, {"text": "Una cantidad estrechamente relacionada con r² pero conceptualmente muy diferente es el coeficiente de correlación, el cual, como mencionamos en el capítulo 1, es una medida del grado de asociación entre dos variables. Algunas propiedades de r son las siguientes: Puede tener signo positivo o negativo. Cae entre los límites de −1 y +1. Es simétrico por naturaleza. Es independiente del origen y de la escala. Es una medida de asociación lineal o dependencia lineal solamente.", "title": "Coeficiente de correlación r y sus propiedades", "eq": "¿Por qué el coeficiente de correlación no puede capturar relaciones no lineales entre variables?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: r (correlación, −1 a +1, mide dirección y fuerza de asociación lineal) vs. r² (determinación, 0 a 1, mide proporción de variación explicada). r = ±√r².", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: r = 0 NO implica independencia. Y = X² es una relación exacta pero r = 0 porque la correlación solo mide asociación lineal.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Correlación no implica causalidad. Un r alto entre consumo de helado y ahogamientos no significa que uno cause al otro; ambos dependen de la temperatura.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: La distinción entre correlación y causalidad fue introducida en el Capítulo 1.", "c": "006B6B", "b": true}]}, {"text": "La ecuación (3.7.1) es la función de consumo agregada keynesiana (es decir, para la economía en su conjunto). Como muestra esta ecuación, la propensión marginal a consumir (PMC) es de cerca de 0.72, lo que indica que si el ingreso real se incrementa un dólar, el gasto promedio de consumo personal aumenta casi 72 centavos. Según la teoría keynesiana, se espera que la PMC se sitúe entre 0 y 1. El valor de r² de 0.9983 significa que más o menos 99% de la variación en el consumo personal se explica por la variación en el PIB.", "title": "Ejemplo: función de consumo keynesiana de EE.UU. (1960-2005)", "eq": "¿Por qué el intercepto negativo de la función de consumo carece de interpretación económica?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: PMC (Propensión Marginal a Consumir) = β̂₂ = 0.72: de cada dólar adicional de ingreso, se consume 72 centavos. La teoría keynesiana predice 0 < PMC < 1.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: El r² = 0.9983 es típico de series de tiempo macroeconómicas donde ambas variables tienen tendencia creciente. No necesariamente indica un modelo superior.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: Este ejemplo aplica MCO a datos de series de tiempo (1960-2005). El supuesto de no autocorrelación (Supuesto 5) podría no cumplirse aquí.", "c": "5B2C8C", "b": true}]}, {"text": "En la ecuación (3.7.2) se observa que si el gasto total se incrementa una rupia, en promedio, el gasto en alimentos aumenta casi 44 paisas (1 rupia = 100 paisas). Si el gasto total fuera nulo (cero), el gasto promedio en alimentos sería de más o menos 94 rupias. El valor de r² de casi 0.37 significa que sólo 37% de la variación en el gasto alimentario se explica por el gasto total. Esto puede parecer un valor más bien bajo, pero, como veremos después, en los datos transversales suelen obtenerse valores bajos de r², quizá debido a la diversidad de unidades de la muestra.", "title": "Ejemplo: gasto alimentario en India (datos transversales)", "eq": "¿Por qué los datos transversales tienden a producir valores de r² más bajos que las series de tiempo?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: En datos transversales, la heterogeneidad entre individuos (familias con diferentes gustos, tamaños, culturas) produce mayor variación no explicada, resultando en r² más bajos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: r² = 0.9983 (series de tiempo, EE.UU.) vs. r² = 0.37 (transversal, India). El tipo de datos influye sistemáticamente en el r² observado.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: ¿Un r² de 0.37 significa que el modelo es malo? No necesariamente: en datos transversales, capturar 37% de la variación con una sola variable puede ser sustancial.", "c": "7B5800", "b": true}]}, {"text": "Pero en la práctica, ¿cómo saber si se mantiene la propiedad MELI? Por ejemplo, ¿cómo se puede averiguar si los estimadores de MCO son insesgados? La respuesta proviene de los llamados experimentos Monte Carlo, los cuales son, en esencia, experimentos de muestreo o de simulación en computadora. Tomamos los promedios de estos 100 valores estimados y los denominamos β̄̂₁ y β̄̂₂. Si estos valores promedio son más o menos los mismos que los valores verdaderos de β₁ y β₂ supuestos en el paso 1, mediante este experimento Monte Carlo se \"establece\" que, en efecto, los estimadores de mínimos cuadrados son insesgados.", "title": "Experimentos Monte Carlo para verificar propiedades de MCO", "eq": "¿Por qué los experimentos Monte Carlo son especialmente útiles para estudiar propiedades en muestras pequeñas?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Experimento Monte Carlo: simulación por computadora donde se conocen los parámetros verdaderos, se generan múltiples muestras y se verifica si los estimadores recuperan los valores verdaderos en promedio.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si fijamos β₁=20, β₂=0.6, generamos 100 muestras de n=25 con errores aleatorios, y el promedio de los 100 valores de β̂₂ es 0.598, esto confirma empíricamente el insesgamiento.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: Monte Carlo operacionaliza el concepto de muestreo repetido: cada simulación es como extraer una nueva muestra de la misma población.", "c": "5B2C8C", "b": true}]}, {"text": "1. El marco básico del análisis de regresión es el MCRL. 2. El MCRL se basa en un conjunto de supuestos. 3. Con base en estos supuestos, los estimadores de mínimos cuadrados adquieren ciertas propiedades resumidas en el teorema de Gauss-Markov, el cual plantea que dentro de la clase de estimadores lineales insesgados, los estimadores de mínimos cuadrados tienen una varianza mínima. En resumen, son MELI. 4. La precisión de los estimadores de MCO se mide por sus errores estándar. 5. La bondad del ajuste general del modelo de regresión se mide con el coeficiente de determinación, r². Éste indica qué proporción de la variación en la variable dependiente se explica por la variable explicativa.", "title": "Resumen integrador del Capítulo 3", "eq": "¿Cómo se relacionan entre sí los supuestos del MCRL, el teorema de Gauss-Markov y el coeficiente r²?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONEXIÓN CONCEPTUAL: Cadena lógica del capítulo: Supuestos MCRL → Teorema de Gauss-Markov → MCO es MELI → Errores estándar miden precisión → r² mide bondad de ajuste.", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Los supuestos son la base de todo: si fallan, MCO puede perder insesgamiento (Sup. 3), eficiencia (Sup. 4, 5) o ser incalculable (Sup. 6, 7).", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El Capítulo 4 agrega el supuesto de normalidad y el Capítulo 5 construye sobre estos fundamentos para pruebas de hipótesis.", "c": "2D2D8F", "b": true}]}], "retrieval": {"q": ["¿Qué establece el teorema de Gauss-Markov y cuáles son sus implicaciones para los estimadores MCO?", "¿Cuál es la diferencia entre homoscedasticidad y heteroscedasticidad, y cómo afecta cada una a los estimadores MCO?", "¿Cómo se interpreta el coeficiente de determinación r² y por qué sus valores difieren entre datos de series de tiempo y datos transversales?", "Enumere y explique brevemente los 7 supuestos del modelo clásico de regresión lineal (MCRL)."], "a": ["El teorema de Gauss-Markov establece que, dados los supuestos del MCRL (linealidad en parámetros, X fija o independiente del error, E(ui)=0, homoscedasticidad, no autocorrelación, n>k, variabilidad en X), los estimadores MCO son MELI: Mejor Estimador Lineal Insesgado. Esto significa que tienen la menor varianza posible dentro de la clase de todos los estimadores que son simultáneamente lineales (funciones lineales de Y) e insesgados (su valor esperado iguala al parámetro verdadero). Si se viola cualquier supuesto, MCO puede perder la propiedad de varianza mínima, aunque en algunos casos mantiene el insesgamiento.", "Homoscedasticidad (var(ui|Xi) = σ², constante) significa que la dispersión de las perturbaciones es igual para todos los valores de X. Heteroscedasticidad (var(ui|Xi) = σ²i, variable) significa que la dispersión cambia según X. Con heteroscedasticidad, los estimadores MCO siguen siendo insesgados y consistentes, pero ya NO son eficientes (pierden la propiedad de varianza mínima). Además, los errores estándar calculados con la fórmula convencional son incorrectos, lo que invalida las pruebas de hipótesis basadas en ellos.", "El coeficiente r² = SCE/SCT = 1 − SCR/SCT mide la proporción de la variación total de Y explicada por el modelo de regresión. Va de 0 (ninguna explicación) a 1 (ajuste perfecto). En series de tiempo, r² tiende a ser alto (ej. 0.99 en consumo-PIB de EE.UU.) porque ambas variables comparten tendencias temporales. En datos transversales, r² es menor (ej. 0.37 en gasto alimentario de India) porque la diversidad entre individuos genera mucha variación no explicada por una sola variable. Un r² bajo no implica un mal modelo; puede indicar heterogeneidad natural en los datos.", "Los 7 supuestos del MCRL son: (1) Linealidad en parámetros: Yi = β₁ + β₂Xi + ui. (2) X fija o independiente del error: cov(Xi, ui) = 0. (3) Media condicional cero: E(ui|Xi) = 0. (4) Homoscedasticidad: var(ui) = σ² constante. (5) No autocorrelación: cov(ui, uj) = 0 para i≠j. (6) n > número de parámetros. (7) Variabilidad en X: var(X) > 0, sin valores atípicos extremos. Estos supuestos garantizan que MCO sea MELI por el teorema de Gauss-Markov."]}}, {"title": "CAPÍTULO 4: MODELO CLÁSICO DE REGRESIÓN LINEAL NORMAL (MCRLN)", "paragraphs": [{"text": "La llamada teoría clásica de la inferencia estadística consta de dos ramas, a saber: estimación y pruebas de hipótesis. Hasta el momento hemos estudiado el tema de la estimación de los parámetros del modelo de regresión lineal (con dos variables). Mediante el método de MCO fue posible estimar los parámetros β1, β2 y σ². Con los supuestos del modelo clásico de regresión lineal (MCRL) demostramos que los estimadores de dichos parámetros, β̂₁, β̂₂ y σ̂², satisfacen varias propiedades estadísticas deseables, como el insesgamiento, la varianza mínima, etc. (Recuerde la propiedad MELI.) Observe que, en vista de que son estimadores, sus valores cambiarán de muestra en muestra. Por consiguiente, tales estimadores son variables aleatorias.", "title": "De la estimación a las pruebas de hipótesis: necesidad de distribuciones", "eq": "¿Por qué no basta con estimar los parámetros y es necesario también conocer sus distribuciones de probabilidad?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La inferencia estadística tiene dos ramas: estimación (calcular β̂) y pruebas de hipótesis (evaluar si β̂ es significativamente diferente de un valor teórico). Sin distribuciones de probabilidad, solo tenemos la primera.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Los estimadores MCO son variables aleatorias (cambian de muestra en muestra). Para hacer inferencias sobre los parámetros poblacionales, necesitamos conocer cómo se distribuyen estos estimadores.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: La propiedad MELI del teorema de Gauss-Markov (Cap. 3) no requiere normalidad, pero las pruebas de hipótesis sí la necesitan.", "c": "006B6B", "b": true}]}, {"text": "Para encontrar las distribuciones de probabilidad de los estimadores de MCO, procederemos como sigue. De manera específica, consideramos β̂₂. Como vimos en el apéndice 3A.2, β̂₂ = Σki Yi donde ki = xi/Σx²i. Debido a que ki, las betas, y Xi son fijas, β̂₂ es a fin de cuentas una función lineal de la variable aleatoria ui, aleatoria por suposición. Por tanto, la distribución de probabilidad de β̂₂ (y también de β̂₁) dependerá del supuesto que se hizo respecto de la distribución de probabilidad de ui.", "title": "La distribución de β̂₂ depende de la distribución de ui", "eq": "¿Por qué la distribución del estimador β̂₂ es completamente determinada por la distribución de ui?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: β̂₂ = Σki Yi es una función lineal de Yi, y Yi = β₁ + β₂Xi + ui. Como ki y Xi son fijos, β̂₂ hereda su aleatoriedad exclusivamente de ui.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: Una propiedad de la distribución normal: cualquier función lineal de variables normales también es normal. Si ui ~ N(0, σ²), entonces β̂₂ también será normal.", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Sin supuesto sobre la distribución de ui, el teorema de Gauss-Markov dice que MCO es MELI, pero no podemos construir intervalos de confianza ni hacer pruebas t o F.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las pruebas t y F para los coeficientes de regresión se desarrollan en el Capítulo 5.", "c": "2D2D8F", "b": true}]}, {"text": "El modelo clásico de regresión lineal normal supone que cada ui está normalmente distribuida con Media: E(ui) = 0, Varianza: E(u²i) = σ², cov(ui, uj) = 0 para i ≠ j. Estos supuestos se expresan en forma más compacta como ui ~ N(0, σ²). Como se señala en el apéndice A, para dos variables normalmente distribuidas, una covarianza o correlación cero significa independencia entre las dos variables. Por consiguiente, con el supuesto de normalidad, ui y uj no sólo no están correlacionadas, sino que también están independientemente distribuidas. Por tanto, ui ~ NID(0, σ²) donde NID significa normal e independientemente distribuido.", "title": "Supuesto de normalidad: de MCRL a MCRLN", "eq": "¿Por qué el supuesto de normalidad convierte la no correlación en independencia estadística?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: MCRLN = MCRL + supuesto de normalidad. ui ~ NID(0, σ²): Normal e Independientemente Distribuido con media cero y varianza constante.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: MCRL: cov(ui,uj) = 0 implica solo no correlación. MCRLN: bajo normalidad, no correlación → independencia estadística. Esta distinción es crucial.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: En general, no correlación ≠ independencia. Pero para la distribución normal específicamente, sí son equivalentes. Esto es una propiedad especial de la distribución normal.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: Los supuestos E(ui)=0 y var(ui)=σ² ya estaban en el MCRL (Cap. 3, supuestos 3 y 4). Aquí se mantienen y se añade normalidad.", "c": "006B6B", "b": true}]}, {"text": "¿Por qué se emplea el supuesto de normalidad? Existen diversas razones. 1. Como señalamos en la sección 2.5, ui representa la influencia combinada (sobre la variable dependiente) de un gran número de variables independientes que no se introdujeron explícitamente en el modelo de regresión. Ahora, gracias al conocido teorema central del límite (TCL) en estadística, se puede demostrar que, si existe un gran número de variables aleatorias independientes con idéntica distribución, entonces, con pocas excepciones, la distribución de su suma tiende a ser normal a medida que se incrementa al infinito el número de tales variables.", "title": "Justificación del supuesto de normalidad: Teorema Central del Límite", "eq": "¿En qué condiciones falla la justificación del TCL para asumir normalidad de las perturbaciones?", "anns": [{"t": "◆◆◆ CRÍTICO:\nAUTOR / TEORÍA: Teorema Central del Límite (TCL): la suma de un gran número de variables aleatorias independientes con distribución idéntica tiende a una distribución normal. Justifica que ui (suma de muchos factores omitidos) sea normal.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: Si ui es normal y β̂₂ es función lineal de ui, entonces β̂₂ también es normal. Esto permite usar las distribuciones t, F y χ² para pruebas de hipótesis.", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: En muestras grandes (n > 100), el supuesto de normalidad es menos crítico: por el TCL aplicado a los propios estimadores, las distribuciones t y F siguen siendo válidas aproximadamente.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: ¿Qué pasa si ui no es normal? En muestras pequeñas, las pruebas t y F pueden ser inválidas. En muestras grandes, las aproximaciones asintóticas rescatan la inferencia.", "c": "7B5800", "b": true}]}, {"text": "3. Con el supuesto de normalidad, se derivan con facilidad las distribuciones de probabilidad de los estimadores de MCO, pues, como se explica en el apéndice A, una propiedad de la distribución normal es que cualquier función lineal de variables normalmente distribuidas estará también normalmente distribuida. Como ya analizamos, los estimadores de MCO β̂₁ y β̂₂ son funciones lineales de ui. Por consiguiente, si ui está normalmente distribuida, también lo están β̂₁ y β̂₂, lo cual hace que la tarea de probar hipótesis sea muy fácil. 5. Si trabajamos con una muestra finita o pequeña, con datos de 100 o menos observaciones, la suposición de normalidad desempeña un papel relevante. No sólo contribuye a derivar las distribuciones de probabilidad exactas de los estimadores de MCO, sino también permite utilizar las pruebas estadísticas t, F y χ² para los modelos de regresión.", "title": "La normalidad habilita las pruebas t, F y chi-cuadrada", "eq": "¿Por qué las pruebas t y F requieren el supuesto de normalidad en muestras pequeñas pero no en grandes?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Bajo normalidad de ui: β̂₁ ~ N(β₁, var(β̂₁)), β̂₂ ~ N(β₂, var(β̂₂)). Los estimadores MCO tienen distribución normal exacta, no aproximada.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: La normalidad de los estimadores permite estandarizarlos: Z = (β̂₂ − β₂)/σ_{β̂₂} ~ N(0,1). Al reemplazar σ por su estimador σ̂, la distribución pasa de Z (normal) a t (Student).", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: En muestras pequeñas (n < 100), la normalidad es crucial para obtener distribuciones exactas. En muestras grandes, las distribuciones asintóticas son válidas incluso sin normalidad.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: Las pruebas t y F basadas en estas distribuciones se aplican en el Capítulo 5 para probar hipótesis sobre los coeficientes.", "c": "2D2D8F", "b": true}]}, {"text": "Si suponemos que ui sigue la distribución normal, como en (4.2.5), los estimadores de MCO tienen las propiedades que se mencionan a continuación: 1. Son insesgados. 2. Tienen varianza mínima. En combinación con 1, esto significa que son estimadores insesgados con varianza mínima, o eficientes. 3. Presentan consistencia; es decir, a medida que el tamaño de la muestra aumenta indefinidamente, los estimadores convergen hacia sus verdaderos valores poblacionales. β̂₁ y β̂₂ tienen varianza mínima entre todas las clases de estimadores insesgados, lineales o no lineales. Este resultado, desarrollado por Rao, es muy eficaz porque, a diferencia del teorema de Gauss-Markov, no se limita a la clase de estimadores lineales.", "title": "De MELI a MEI: la normalidad amplía la optimalidad de MCO", "eq": "¿En qué se diferencia la propiedad MEI (bajo normalidad) de la propiedad MELI (sin normalidad)?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: MELI (Gauss-Markov, sin normalidad): varianza mínima entre estimadores lineales insesgados. MEI (con normalidad, resultado de Rao): varianza mínima entre TODOS los estimadores insesgados, lineales o no lineales.", "c": "C00000", "b": true}, {"t": "◆◆◆ CRÍTICO:\nAUTOR / TEORÍA: C.R. Rao demostró que bajo normalidad, MCO es MEI (Mejor Estimador Insesgado), un resultado más fuerte que el de Gauss-Markov que solo garantizaba MELI.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: Consistencia: a medida que n → ∞, los estimadores convergen a los valores verdaderos. Es una propiedad asintótica, diferente del insesgamiento que es de muestra finita.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: Sin normalidad: MELI. Con normalidad: MEI + distribuciones exactas (normal, t, F, χ²). La normalidad es un supuesto con alto rendimiento teórico.", "c": "5B2C8C", "b": true}]}, {"text": "β̂₁ (al ser una función lineal de ui) está normalmente distribuida con Media: E(β̂₁) = β₁ y var(β̂₁) = [ΣX²i / (n Σx²i)]σ². O, en forma más compacta, β̂₁ ~ N(β₁, σ²_{β̂₁}). Entonces, la variable Z = (β̂₁ − β₁)/σ_{β̂₁} sigue la distribución normal estándar, N(0, 1). β̂₂ está normalmente distribuida con Media: E(β̂₂) = β₂ y var(β̂₂) = σ²/Σx²i. (n − 2)(σ̂²/σ²) está distribuida como la distribución χ² (ji cuadrada), con (n − 2) gl.", "title": "Distribuciones exactas de β̂₁, β̂₂ y σ̂² bajo normalidad", "eq": "¿Por qué la distribución de σ̂² se relaciona con chi-cuadrada y no con la normal?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Bajo normalidad: β̂₁ ~ N(β₁, σ²_{β̂₁}), β̂₂ ~ N(β₂, σ²_{β̂₂}), y (n−2)σ̂²/σ² ~ χ²(n−2). Estas tres distribuciones son la base de toda la inferencia en regresión.", "c": "2E75B6", "b": true}, {"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La estandarización Z = (β̂₂ − β₂)/σ_{β̂₂} ~ N(0,1) permite convertir cualquier estimador normal a escala estándar para calcular probabilidades y construir intervalos.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: β̂₁ y β̂₂ se distribuyen independientemente de σ̂². Esto es importante porque permite hacer inferencias sobre los coeficientes sin que σ̂² interfiera.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: En el Capítulo 5, al reemplazar σ por σ̂ en Z, la distribución pasa de N(0,1) a t(n−2), base de las pruebas de significancia.", "c": "2D2D8F", "b": true}]}, {"text": "Un método de estimación puntual con algunas propiedades teóricamente más fuertes que las del método de MCO es el método de máxima verosimilitud (MV). Para el lector que sólo tiene un interés general, baste aclarar que si se supuso que ui está normalmente distribuida, como lo hemos hecho por las razones expuestas, los estimadores de MV y MCO de los coeficientes de regresión, los β, son idénticos, y esto es válido para regresiones simples al igual que para las regresiones múltiples. El estimador de MV de σ² es Σû²i/n. Este estimador es sesgado, en tanto que el estimador de MCO de σ² = Σû²i/(n−2), como vimos, es insesgado.", "title": "Equivalencia MCO-MV bajo normalidad y sesgo del estimador de varianza", "eq": "¿Por qué el estimador de MV de σ² es sesgado mientras que el de MCO es insesgado?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Bajo normalidad, los estimadores de MV y MCO de β₁ y β₂ son idénticos. Difieren solo en la estimación de σ²: MV usa n en el denominador (sesgado), MCO usa (n−2) (insesgado).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: σ̂²_MCO = Σû²i/(n−2) vs. σ̃²_MV = Σû²i/n. E(σ̃²_MV) = σ² − (2/n)σ², subestima σ² en muestras pequeñas. El sesgo desaparece cuando n → ∞.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Para muestras grandes, MCO y MV son esencialmente equivalentes. MV tiene aplicación más amplia: se aplica también a modelos no lineales donde MCO no se usa.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Si los estimadores de coeficientes son idénticos, ¿por qué estudiar MV? Porque MV tiene propiedades asintóticas superiores y se generaliza a modelos más complejos (Cap. 14).", "c": "7B5800", "b": true}]}, {"text": "1. En este capítulo analizamos el modelo clásico de regresión lineal normal (MCRLN). 2. Este modelo difiere del modelo clásico de regresión lineal (MCRL) al suponer específicamente que el término de perturbación, ui, que forma parte del modelo de regresión, está normalmente distribuido. El MCRL no requiere ningún supuesto sobre la distribución de probabilidad de ui; sólo requiere que el valor de la media de ui sea cero y su varianza sea una constante finita. 3. La justificación teórica del supuesto de normalidad es el teorema central del límite. 4. Sin el supuesto de normalidad, según los otros supuestos analizados en el capítulo 3, el teorema de Gauss-Markov demostró que los estimadores de MCO son MELI. 5. Con el supuesto adicional de normalidad, los estimadores de MCO no sólo son los mejores estimadores insesgados (MEI) sino que también siguen distribuciones de probabilidad bien conocidas.", "title": "Resumen integrador del Capítulo 4: MCRLN", "eq": "¿Cuál es la contribución principal del supuesto de normalidad respecto al MCRL sin normalidad?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONEXIÓN CONCEPTUAL: Progresión lógica: MCRL (Cap. 3) → MCO es MELI. MCRLN (Cap. 4) → MCO es MEI + distribuciones exactas (normal, t, F, χ²). El supuesto de normalidad amplifica las propiedades de MCO.", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: MCRL: no requiere distribución de ui, solo E(ui)=0 y var(ui)=σ². MCRLN: agrega ui ~ N(0, σ²). El MCRL es el marco mínimo; el MCRLN añade normalidad para habilitar inferencia.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El Capítulo 5 utiliza las distribuciones derivadas aquí para construir intervalos de confianza y pruebas de hipótesis formales.", "c": "2D2D8F", "b": true}]}], "retrieval": {"q": ["¿Qué diferencia al MCRLN del MCRL y por qué es necesario el supuesto adicional de normalidad?", "¿Cómo justifica el Teorema Central del Límite el supuesto de normalidad de las perturbaciones ui?", "¿En qué se diferencia la propiedad MEI (bajo normalidad) de la propiedad MELI (teorema de Gauss-Markov)?", "¿Cuáles son las distribuciones de β̂₁, β̂₂ y σ̂² bajo el supuesto de normalidad y por qué son importantes?"], "a": ["El MCRLN añade al MCRL el supuesto de que ui ~ N(0, σ²). El MCRL solo requiere E(ui)=0 y var(ui)=σ², sin especificar distribución, y garantiza MELI vía Gauss-Markov. El supuesto de normalidad es necesario porque: (1) permite derivar distribuciones exactas de los estimadores para hacer pruebas de hipótesis; (2) amplía la optimalidad de MCO de MELI a MEI (varianza mínima entre todos los insesgados, no solo los lineales); (3) habilita las pruebas t, F y χ² que son fundamentales para la inferencia en muestras finitas.", "El TCL establece que la suma de un gran número de variables aleatorias independientes tiende a distribuirse normalmente. Como ui representa la influencia combinada de muchas variables omitidas del modelo, cada una con efecto pequeño, su suma tiende a la normalidad. Incluso una variante del TCL permite que las variables no sean estrictamente independientes ni numerosas, y la suma aún puede ser normal. Esto proporciona justificación teórica para asumir ui ~ N(0, σ²).", "MELI (Gauss-Markov): bajo los supuestos del MCRL sin normalidad, MCO tiene varianza mínima dentro de la clase de estimadores lineales insesgados. MEI (resultado de Rao, con normalidad): MCO tiene varianza mínima dentro de toda la clase de estimadores insesgados, lineales O no lineales. MEI es estrictamente más fuerte que MELI: no existe ningún estimador insesgado (de cualquier tipo) que tenga menor varianza que MCO bajo normalidad.", "Bajo normalidad: β̂₁ ~ N(β₁, σ²_{β̂₁}) y β̂₂ ~ N(β₂, σ²_{β̂₂}) tienen distribución normal exacta. (n−2)σ̂²/σ² ~ χ²(n−2) tiene distribución chi-cuadrada. Además, β̂₁ y β̂₂ son independientes de σ̂². Estas distribuciones son importantes porque permiten: (a) estandarizar los estimadores para calcular probabilidades, (b) construir intervalos de confianza, (c) realizar pruebas de hipótesis usando las distribuciones t y F en el Capítulo 5."]}}, {"title": "CAPÍTULO 5: REGRESIÓN CON DOS VARIABLES: ESTIMACIÓN POR INTERVALOS Y PRUEBAS DE HIPÓTESIS", "paragraphs": [{"text": "Como señalamos en el capítulo 4, la estimación y las pruebas de hipótesis constituyen las dos ramas principales de la estadística clásica. La teoría de la estimación consta de dos partes: estimación puntual y estimación por intervalos. En los dos capítulos anteriores estudiamos a fondo la estimación puntual, en donde se introdujeron los métodos MCO y MV de la estimación puntual. En este capítulo consideraremos primero la estimación por intervalos y luego trataremos el tema de las pruebas de hipótesis, muy relacionado con la estimación por intervalos.", "title": "Las dos ramas de la estadística clásica", "eq": "¿Por qué la estimación por intervalos complementa a la estimación puntual en la inferencia estadística?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Las dos ramas principales de la estadística clásica son la estimación (puntual e intervalos) y las pruebas de hipótesis. Ambas se complementan para hacer inferencias sobre parámetros poblacionales.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\n↩ RETOMA: Los métodos MCO y MV de estimación puntual presentados en los capítulos 3 y 4.", "c": "006B6B", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: La estimación por intervalos y las pruebas de hipótesis están íntimamente relacionadas, como se demostrará a lo largo del capítulo.", "c": "5B2C8C", "b": true}]}, {"text": "Para poner en orden las ideas, consideremos el ejemplo de los salarios y el nivel de escolaridad del capítulo 3. La ecuación (3.6.1) muestra que el incremento promedio estimado del salario medio por hora relacionado con un año de aumento en la escolaridad (βˆ2) es de 0.7240, que constituye una cifra estimada (puntual) del valor poblacional desconocido β2. ¿Qué tan confiable es esta estimación? Como mencionamos en el capítulo 3, debido a las fluctuaciones muestrales, es probable que una sola estimación difiera del valor verdadero, aunque en un muestreo repetido se espera que el promedio de los valores sea igual al valor verdadero. [Nota: E(βˆ2) = β2.] Ahora, en estadística, la confiabilidad de un estimador puntual se mide por su error estándar. Por tanto, en lugar de depender de un solo estimador puntual, se puede construir un intervalo alrededor del estimador puntual, por ejemplo, dentro de dos o tres errores estándar a cada lado del estimador puntual, tal que este intervalo tenga, por ejemplo, 95% de probabilidad de incluir al verdadero valor del parámetro. Ésta es, a grandes rasgos, la idea básica de la estimación por intervalos.", "title": "Idea básica de la estimación por intervalos", "eq": "¿Qué ventaja ofrece un intervalo de confianza sobre una simple estimación puntual?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La estimación por intervalos construye un rango alrededor del estimador puntual con una probabilidad específica de contener el verdadero valor del parámetro, proporcionando una medida de la incertidumbre de la estimación.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: En el ejemplo salarios-escolaridad, βˆ2 = 0.7240 es una estimación puntual; el intervalo de confianza proporciona un rango de valores plausibles para el verdadero β2.", "c": "1A5C38", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: La confiabilidad de un estimador puntual se mide por su error estándar. A mayor error estándar, menor confiabilidad y más amplio el intervalo.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: La propiedad de insesgamiento E(βˆ2) = β2 del capítulo 3.", "c": "006B6B", "b": true}]}, {"text": "Para ser más específico, supongamos que se desea encontrar qué tan \"cerca\" está, por ejemplo, βˆ2 de β2. Con este fin, se trata de encontrar dos números positivos, δ y α, este último situado entre 0 y 1, de modo que la probabilidad de que el intervalo aleatorio (βˆ2 − δ, βˆ2 + δ) contenga al verdadero β2 sea 1 − α. Simbólicamente, Pr (βˆ2 − δ ≤ β2 ≤ βˆ2 + δ) = 1 − α. Tal intervalo, si existe, se conoce como intervalo de confianza; a 1 − α se le denomina coeficiente de confianza; y α (0 < α < 1) se conoce como nivel de significancia. Los extremos del intervalo de confianza se conocen como límites de confianza (también denominados valores críticos), con βˆ2 − δ como límite de confianza inferior y βˆ2 + δ como límite de confianza superior.", "title": "Definición formal del intervalo de confianza", "eq": "¿Qué relación existe entre el nivel de significancia α y el coeficiente de confianza 1 − α?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Intervalo de confianza: intervalo aleatorio (βˆ2 − δ, βˆ2 + δ) con probabilidad 1 − α de contener al verdadero β2. Coeficiente de confianza = 1 − α. Nivel de significancia = α.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Los límites de confianza (valores críticos) son los extremos del intervalo. El límite inferior es βˆ2 − δ y el superior es βˆ2 + δ.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\nIMPLICACIÓN: En la práctica, α y 1 − α se expresan en forma porcentual (por ejemplo, α = 5% implica un coeficiente de confianza del 95%).", "c": "C55A11", "b": true}]}, {"text": "La ecuación (5.2.1) no afirma que la probabilidad de que β2 se encuentre entre los límites dados sea 1 − α. Como se supone que β2, aunque se desconoce, es un número fijo, se dice que está o no está dentro del intervalo. La ecuación (5.2.1) establece que, al utilizar el método descrito en este capítulo, la probabilidad de construir un intervalo que contenga β2 es 1 − α. El intervalo (5.2.1) es un intervalo aleatorio; es decir, variará de una muestra a la siguiente debido a que se basa en βˆ2, el cual es aleatorio. Como el intervalo de confianza es aleatorio, los enunciados probabilísticos que le corresponden deben entenderse en un sentido de largo plazo, es decir, para muestreo repetido.", "title": "Interpretación correcta del intervalo de confianza", "eq": "¿Por qué no podemos decir que 'la probabilidad de que β2 esté en el intervalo es 95%' una vez calculado el intervalo?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: El intervalo de confianza es aleatorio (varía de muestra a muestra). Una vez calculado con datos específicos, el intervalo es fijo, y β2 está o no está dentro de él. La probabilidad es 1 o 0, no 1 − α.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: La interpretación correcta es: si se construyen muchos intervalos con probabilidad 1 − α, a la larga, en 1 − α de los casos contendrán el verdadero valor del parámetro.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: Esta distinción entre intervalo aleatorio e intervalo fijo es una fuente frecuente de confusión en la interpretación frecuentista de la probabilidad.", "c": "7B5800", "b": true}]}, {"text": "En el capítulo 4, sección 4.3, demostramos que con el supuesto de normalidad de ui, los estimadores de MCO βˆ1 y βˆ2 son en sí mismos normalmente distribuidos con medias y varianzas allí establecidas. Pero pocas veces se conoce σ² y, en la práctica, está determinada por el estimador insesgado σˆ². Si se reemplaza σ por σˆ, la variable t = (βˆ2 − β2)/ee(βˆ2) sigue la distribución t con n − 2 gl. Por consiguiente, en lugar de utilizar la distribución normal, se puede utilizar la distribución t para construir un intervalo de confianza para β2: Intervalo de confianza para β2 a 100(1 − α)%: βˆ2 ± tα/2 ee(βˆ2).", "title": "Intervalo de confianza usando la distribución t", "eq": "¿Por qué se usa la distribución t en lugar de la normal cuando σ² es desconocida?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Intervalo de confianza para β2 = βˆ2 ± tα/2 · ee(βˆ2), con n − 2 grados de libertad. Se usa la distribución t porque σ² se estima con σˆ².", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Cuando σ² es conocida se usa la distribución normal Z; cuando σ² es estimada con σˆ², se usa la distribución t de Student con n − 2 gl.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: La amplitud del intervalo de confianza es proporcional al error estándar del estimador. Mayor error estándar = mayor incertidumbre = intervalo más amplio.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\nAUTOR / TEORÍA: William Sealy Gosset ('Student') desarrolló la distribución t para muestras pequeñas cuando la varianza poblacional es desconocida.", "c": "2E75B6", "b": true}]}, {"text": "Como señalamos en el capítulo 4, sección 4.3, según el supuesto de normalidad, la variable χ² = (n − 2)σˆ²/σ² sigue la distribución χ² con n − 2 gl. Por tanto, con la distribución χ² se establece el intervalo de confianza para σ²: Pr[(n − 2)σˆ²/χ²α/2 ≤ σ² ≤ (n − 2)σˆ²/χ²1−α/2] = 1 − α, que da el intervalo de confianza a 100(1 − α)% para σ².", "title": "Intervalo de confianza para la varianza σ²", "eq": "¿Por qué el intervalo de confianza para σ² es asimétrico, a diferencia del de β2?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: La variable (n − 2)σˆ²/σ² sigue una distribución χ² con n − 2 gl. Esto permite construir intervalos de confianza para σ².", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: A diferencia de la distribución t (simétrica), la distribución χ² es asimétrica, por lo que los valores críticos superior e inferior no son simétricos alrededor del valor central.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\nEJEMPLO: Para el ejemplo salarios-escolaridad con σˆ² = 0.8936, α = 5% y 11 gl, el intervalo es 0.4484 ≤ σ² ≤ 2.5760.", "c": "1A5C38", "b": true}]}, {"text": "El problema de las pruebas de hipótesis estadísticas puede plantearse sencillamente de la siguiente manera: ¿es compatible o no lo es una observación o un hallazgo dados, según algunas hipótesis planteadas? La palabra \"compatible\" se utiliza aquí en el sentido de que la observación es lo \"bastante\" cercana al valor hipotético, de forma que no se rechaza la hipótesis planteada. En el lenguaje de estadística, la hipótesis planteada se conoce como hipótesis nula, y se denota con el símbolo H0. La hipótesis nula suele probarse frente a una hipótesis alternativa (también conocida como hipótesis mantenida) denotada con H1.", "title": "Fundamentos de las pruebas de hipótesis", "eq": "¿Cuál es la diferencia entre no rechazar una hipótesis nula y demostrar que es verdadera?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Hipótesis nula (H0): hipótesis planteada que se somete a prueba. Hipótesis alternativa (H1): hipótesis contra la cual se prueba H0. La prueba determina si los datos son 'compatibles' con H0.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Hipótesis simple: especifica el valor preciso del parámetro (H0: β2 = 0.5). Hipótesis compuesta: no especifica un valor único (H1: β2 ≠ 0.5).", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: Hay dos métodos complementarios para probar hipótesis: el intervalo de confianza y la prueba de significancia.", "c": "5B2C8C", "b": true}]}, {"text": "Un enfoque alterno pero complementario al de intervalos de confianza para probar hipótesis estadísticas es el método de la prueba de significancia, desarrollado en forma independiente por R. A. Fisher y conjuntamente por Neyman y Pearson. En términos generales, una prueba de significancia es un procedimiento que utiliza los resultados muestrales para verificar la verdad o falsedad de una hipótesis nula. La idea básica de las pruebas de significancia es la de un estadístico de prueba (un estimador) y su distribución muestral según la hipótesis nula. La decisión de aceptar o rechazar H0 se toma con base en el valor del estadístico de prueba obtenido con los datos disponibles.", "title": "La prueba de significancia: Fisher, Neyman y Pearson", "eq": "¿Cómo se relaciona la distribución muestral del estadístico de prueba con la decisión de rechazar o no H0?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Prueba de significancia: procedimiento basado en un estadístico de prueba y su distribución muestral bajo H0 para decidir si rechazar o no la hipótesis nula.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: R. A. Fisher desarrolló la prueba de significancia de forma independiente. Neyman y Pearson la desarrollaron conjuntamente con un marco más formal de errores tipo I y II.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Región de aceptación: zona donde el estadístico de prueba es 'compatible' con H0. Región de rechazo (región crítica): zona donde se rechaza H0.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: El enfoque de intervalos de confianza y el de prueba de significancia son complementarios y producen conclusiones idénticas.", "c": "5B2C8C", "b": true}]}, {"text": "Como utilizamos la distribución t, el anterior procedimiento de prueba se llama, apropiadamente, prueba t. En el lenguaje de las pruebas de significancia, se dice que un estadístico es estadísticamente significativo si el valor del estadístico de prueba cae en la región crítica. En este caso, se rechaza la hipótesis nula. De la misma manera, se dice que una prueba no es estadísticamente significativa si el valor del estadístico de prueba cae en la región de aceptación. En esta situación, no se rechaza la hipótesis nula.", "title": "La prueba t y significancia estadística", "eq": "¿Qué significa exactamente que un coeficiente sea 'estadísticamente significativo'?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Prueba t: estadístico t = (βˆ2 − β2*)/ee(βˆ2). Si |t| > tα/2 (cae en región crítica), se rechaza H0 y el resultado es 'estadísticamente significativo'.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Prueba bilateral (dos colas): H1: β2 ≠ β2*, se rechazan valores extremos en ambas colas. Prueba unilateral (una cola): H1: β2 > β2* o H1: β2 < β2*, se rechaza solo en una cola.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: La prueba t se generaliza al modelo de regresión múltiple en los capítulos 7-8 para probar la significancia de coeficientes individuales.", "c": "2D2D8F", "b": true}]}, {"text": "Al \"aceptar\" una hipótesis nula siempre se debe tener presente que puede existir otra hipótesis nula igualmente compatible con los datos. Es preferible, por tanto, decir que se puede aceptar la hipótesis nula en lugar de decir que la aceptamos. Mejor aún, de la misma manera que en un tribunal se pronuncia un veredicto de \"no culpable\" en lugar de decir \"inocente\", así la conclusión de una prueba estadística es la de \"no rechazar\" en lugar de \"aceptar\".", "title": "No rechazar versus aceptar la hipótesis nula", "eq": "¿Por qué es más correcto decir 'no se rechaza H0' que decir 'se acepta H0'?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: 'No rechazar H0' ≠ 'H0 es verdadera'. Puede haber múltiples hipótesis nulas compatibles con los datos. La analogía judicial es precisa: 'no culpable' ≠ 'inocente'.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Si H0: β2 = 0.70 no se rechaza (t = 0.34) y tampoco H0: β2 = 0.60 (t = 1.77), ambas hipótesis son 'compatibles' con los datos. ¿Cuál es la 'verdadera'?", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nAUTOR / TEORÍA: Kmenta (1971) propone la analogía del tribunal para enfatizar que la conclusión correcta es 'no rechazar' en lugar de 'aceptar'.", "c": "2E75B6", "b": true}]}, {"text": "La hipótesis nula que es objeto frecuente de prueba en el trabajo empírico es H0: β2 = 0, es decir, el coeficiente de la pendiente es cero. Esta hipótesis nula de \"cero\" es un mecanismo para establecer si Y tiene relación con X, la variable explicativa. Si el número de grados de libertad es 20 o más, y si α, el nivel de significancia, se fija en 0.05, se rechaza la hipótesis nula β2 = 0 si el valor de t [= βˆ2/ee(βˆ2)] calculado a partir de (5.3.2) es superior a 2 en valor absoluto.", "title": "La regla práctica '2t' y la hipótesis nula cero", "eq": "¿Por qué probar H0: β2 = 0 es más fundamental que probar otros valores hipotéticos de β2?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Regla práctica '2t': con gl ≥ 20 y α = 0.05, se rechaza H0: β2 = 0 si |t| > 2. Esto establece si existe relación lineal entre Y y X.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Si β2 = 0 (no hay relación entre Y y X), no tiene sentido probar otros valores hipotéticos de β2 como 0.3 o 0.5.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n❓ REFLEXIÓN: La regla '2t' es una aproximación útil para gl ≥ 20, pero para gl menores se debe consultar la tabla t para obtener el valor crítico exacto.", "c": "7B5800", "b": true}]}, {"text": "El talón de Aquiles del método clásico de la prueba de hipótesis es su arbitrariedad al seleccionar α. Una vez obtenido un estadístico de prueba (es decir, el estadístico t) en un ejemplo dado, ¿por qué no tan sólo consultar la tabla estadística adecuada y encontrar la probabilidad real de obtener un valor del estadístico de prueba tan grande o mayor que el obtenido en el ejemplo? Esta probabilidad se denomina valor p (es decir, valor de probabilidad), también conocido como nivel observado o exacto de significancia, o probabilidad exacta de cometer un error tipo I. Más técnicamente, el valor p se define como nivel de significancia más bajo al cual puede rechazarse una hipótesis nula.", "title": "El valor p: nivel exacto de significancia", "eq": "¿Cómo resuelve el valor p el problema de la selección arbitraria del nivel de significancia α?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Valor p = probabilidad de obtener un estadístico de prueba tan extremo o más que el observado, bajo H0. Es el nivel de significancia más bajo al cual se puede rechazar H0.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Si el valor p es pequeño, los datos no apoyan H0 y se rechaza con confianza. Es preferible reportar el valor p y dejar que el investigador decida, en lugar de fijar α arbitrariamente.", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Con H0: β2 = 0.5 y t = 3.2 (11 gl), el valor p ≈ 0.00001. Esto es mucho menor que los niveles convencionales de 1%, 5% o 10%.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nDISTINCIÓN: Relación entre valor p y α: si se fija α = valor p, no hay conflicto. Es mejor reportar el valor p que fijar α arbitrariamente.", "c": "C00000", "b": true}]}, {"text": "El punto de toda esta exposición es que no se debe confundir la significancia estadística con la significancia práctica o económica. Como afirma Goldberger: Cuando se especifica una hipótesis nula, digamos βj = 1, lo que se busca es que βj esté cercano a 1, tan cerca que para todos los propósitos prácticos pueda tratarse como si fuera 1. Pero que 1.1 sea \"prácticamente lo mismo que\" 1.0 es un asunto de economía, no de estadística. El asunto no se resuelve con una prueba de hipótesis. Puede ser una buena idea reservar el término \"significancia\" para el concepto estadístico, y adoptar la palabra \"sustancial\" para el económico.", "title": "Significancia estadística versus significancia práctica", "eq": "¿Por qué un coeficiente puede ser estadísticamente significativo pero económicamente irrelevante?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Significancia estadística ≠ significancia práctica (económica). Un coeficiente puede ser estadísticamente diferente de cero pero económicamente trivial, especialmente con muestras grandes.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: Goldberger (1991) propone reservar 'significancia' para estadística y 'sustancial' para la importancia económica. McCloskey y Ziliak (1996) también critican el abuso de las pruebas de significancia.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: PMC de 0.72 vs 0.74: estadísticamente diferente pero el multiplicador pasa de 3.57 a 3.84. ¿Es esa diferencia prácticamente importante para reactivar la economía?", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nIMPLICACIÓN: Con muestras muy grandes, casi todas las H0 se rechazan. La magnitud de los valores estimados puede importar más que su significancia estadística.", "c": "C55A11", "b": true}]}, {"text": "En el capítulo 3, sección 3.5, elaboramos la siguiente identidad: SCT = SCE + SCR, la cual fragmenta la suma de cuadrados total (SCT) en dos componentes: la suma de cuadrados explicada (SCE) y la suma de cuadrados de residuos (SCR). El estudio de estos componentes de SCT se conoce como análisis de varianza (ANOVA) desde el punto de vista de la regresión. Si suponemos que las perturbaciones ui están normalmente distribuidas, lo cual se cumple para el MCRLN, y si la hipótesis nula (H0) es que β2 = 0, puede demostrarse que la variable F = SCP de SCE / SCP de SCR sigue la distribución F con 1 gl en el numerador y (n − 2) gl en el denominador.", "title": "Análisis de varianza (ANOVA) y la prueba F", "eq": "¿Cuál es la relación entre la prueba F del ANOVA y la prueba t para β2 = 0?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: ANOVA descompone SCT = SCE + SCR. La razón F = SCP de SCE / SCP de SCR sigue distribución F(1, n−2) bajo H0: β2 = 0.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONEXIÓN CONCEPTUAL: Para el modelo de dos variables, F(1,k) = t²(k). Las pruebas t y F son equivalentes para probar H0: β2 = 0.", "c": "5B2C8C", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Si β2 = 0, tanto SCE como SCR estiman σ². Si β2 ≠ 0, SCE sobreestima σ² porque incluye β2²Σxi². Una F grande evidencia β2 ≠ 0.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: La prueba F será fundamental en regresión múltiple (caps. 7-8) para probar la significancia conjunta de múltiples coeficientes.", "c": "2D2D8F", "b": true}]}, {"text": "Con base en los datos muestrales se obtuvo la regresión muestral. ¿De qué sirve esta regresión histórica? Para \"predecir\" o \"pronosticar\" el salario promedio futuro Y correspondiente a algún nivel dado de escolaridad X. Ahora, hay dos clases de predicciones: 1) la predicción del valor de la media condicional de Y correspondiente a un valor escogido X, por ejemplo, X0, que es el punto sobre la línea de regresión poblacional misma, y 2) la predicción de un valor individual Y correspondiente a X0. Estas dos predicciones se llaman predicción media y predicción individual.", "title": "Predicción media versus predicción individual", "eq": "¿Por qué el intervalo de confianza para la predicción individual es siempre más amplio que para la predicción media?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Predicción media: estima E(Y|X0), el punto sobre la FRP. Predicción individual: estima un valor particular Y0 correspondiente a X0. La predicción individual tiene mayor varianza porque incluye la variabilidad de ui.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: var(Ŷ0) = σ²[1/n + (X0 − X̄)²/Σxi²] para predicción media. var(Y0 − Ŷ0) = σ²[1 + 1/n + (X0 − X̄)²/Σxi²] para predicción individual. El término adicional '1' genera la mayor amplitud.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: La amplitud mínima de las bandas de confianza ocurre en X0 = X̄ y crece a medida que X0 se aleja de X̄. No extrapolar lejos de la media muestral.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\nEJEMPLO: Para X0 = 20, predicción media: [13.10, 15.83]. Predicción individual: [12.02, 16.91]. El intervalo individual es claramente más amplio.", "c": "1A5C38", "b": true}]}, {"text": "La prueba de normalidad JB es una prueba asintótica, o de muestras grandes. También se basa en los residuos de MCO. Esta prueba calcula primero la asimetría y la curtosis de los residuos de MCO, con el siguiente estadístico de prueba: JB = n[S²/6 + (K − 3)²/24], donde n = tamaño de la muestra, S = coeficiente de asimetría y K = coeficiente de curtosis. Para una variable normalmente distribuida, S = 0 y K = 3. Por tanto, la prueba de normalidad JB constituye una prueba de la hipótesis conjunta de que S y K son 0 y 3, respectivamente. De acuerdo con la hipótesis nula, el estadístico JB sigue la distribución ji cuadrada, con 2 gl.", "title": "Prueba de normalidad Jarque-Bera (JB)", "eq": "¿Por qué es importante verificar la normalidad de los residuos antes de aplicar pruebas t y F?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Estadístico JB = n[S²/6 + (K−3)²/24]. Bajo H0 de normalidad: JB ~ χ²(2). Si JB ≈ 0 (S ≈ 0 y K ≈ 3), no se rechaza normalidad.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: Jarque y Bera (1987) desarrollaron esta prueba asintótica. Para muestras pequeñas, puede no ser confiable.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Las pruebas t, F y χ² requieren normalidad de ui. Si los residuos no son normales, estas pruebas no son válidas en muestras pequeñas.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\nEJEMPLO: Para la regresión salarios-escolaridad: JB = 0.8286, valor p ≈ 0.66. No se rechaza normalidad. Para gasto alimentario India: JB = 0.2576, valor p ≈ 0.88.", "c": "1A5C38", "b": true}]}, {"text": "En la práctica, se debe tener cuidado al determinar α, la probabilidad de cometer un error tipo I, al asignarle valores arbitrarios, como 1, 5 o 10%. Es mejor hacer referencia al valor p del estadístico de prueba. Además, la significancia estadística de una estimación no debe confundirse con su significancia práctica. Por supuesto, las pruebas de hipótesis suponen que el modelo seleccionado para el análisis empírico es adecuado en el sentido de que no viola alguno(s) del(los) supuesto(s) que sirven de base al modelo clásico de regresión lineal normal. Por tanto, las pruebas sobre la bondad del modelo deben preceder a las pruebas de hipótesis.", "title": "Resumen: precauciones en la inferencia estadística", "eq": "¿Cuál es la secuencia correcta: primero probar hipótesis sobre los coeficientes o primero verificar los supuestos del modelo?", "anns": [{"t": "◆◆◆ CRÍTICO:\nIMPLICACIÓN: Las pruebas de bondad del modelo (normalidad, homocedasticidad, etc.) deben preceder a las pruebas de hipótesis sobre los coeficientes. Sin modelo adecuado, las pruebas t y F carecen de validez.", "c": "C55A11", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Tres advertencias clave: (1) no fijar α arbitrariamente, usar valor p; (2) no confundir significancia estadística con práctica; (3) verificar supuestos del modelo antes de interpretar resultados.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: El capítulo 13 abordará pruebas de diagnóstico adicionales para evaluar la bondad del modelo de regresión.", "c": "2D2D8F", "b": true}]}], "retrieval": {"q": ["¿Qué es un intervalo de confianza y cómo se interpreta correctamente en el contexto de muestreo repetido?", "Explique la diferencia entre la prueba de hipótesis bilateral (dos colas) y la prueba unilateral (una cola), incluyendo cuándo usar cada una.", "¿Qué es el valor p y por qué se considera superior a fijar α arbitrariamente?", "Describa la relación entre la prueba t y la prueba F en el modelo de regresión con dos variables."], "a": ["Un intervalo de confianza a 100(1−α)% es un rango construido como βˆ2 ± tα/2·ee(βˆ2) que tiene probabilidad 1−α de contener al verdadero β2. La interpretación correcta es de largo plazo: si se construyen muchos intervalos de este tipo, el 100(1−α)% contendrán el verdadero valor. Una vez calculado con datos específicos, el intervalo es fijo y β2 está o no está dentro de él (probabilidad 1 o 0).", "La prueba bilateral (H1: β2 ≠ β2*) considera ambas colas de la distribución y rechaza H0 si |t| > tα/2. Se usa cuando no hay expectativa a priori sobre la dirección del efecto. La prueba unilateral (H1: β2 > β2* o β2 < β2*) usa solo una cola y rechaza si t > tα o t < −tα. Se usa cuando la teoría o evidencia previa indica una dirección específica del efecto.", "El valor p es la probabilidad exacta de obtener un estadístico de prueba tan extremo o más que el observado bajo H0. Es el nivel de significancia más bajo al cual puede rechazarse H0. Es superior a fijar α arbitrariamente porque permite al investigador evaluar la evidencia exacta contra H0 y decidir por sí mismo si el resultado es significativo, en lugar de depender de convenciones como α = 1%, 5% o 10%.", "En el modelo de regresión con dos variables, la prueba F del ANOVA y la prueba t para H0: β2 = 0 son equivalentes: F(1, n−2) = t²(n−2). La prueba F descompone SCT = SCE + SCR y compara la variación explicada con la no explicada. Si β2 = 0, ambos componentes estiman σ². Si β2 ≠ 0, SCE sobreestima σ² y la razón F será grande. Aunque para dos variables basta la prueba t, la prueba F será fundamental en regresión múltiple para probar la significancia conjunta de múltiples coeficientes."]}}, {"title": "CAPÍTULO 6: EXTENSIONES DEL MODELO DE REGRESIÓN LINEAL CON DOS VARIABLES", "paragraphs": [{"text": "Hay ocasiones en las cuales la función de regresión poblacional (FRP) de dos variables adquiere la siguiente forma: Yi = β2Xi + ui. En este modelo, el término del intercepto está ausente o es cero, lo cual explica el nombre: regresión a través del origen. A manera de ilustración consideremos el modelo de asignación de precios de activos de capital (CAPM, del inglés capital asset pricing model) de la teoría moderna de portafolios, la cual, en su versión de prima por riesgo, se expresa como (ERi − rf) = βi(ERm − rf).", "title": "Regresión a través del origen y el modelo CAPM", "eq": "¿Bajo qué condiciones teóricas es apropiado omitir el intercepto en un modelo de regresión?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Regresión a través del origen: Yi = β2Xi + ui (sin intercepto). El estimador MCO es βˆ2 = ΣXiYi/ΣXi², con varianza σ²/ΣXi² y gl = n − 1.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: CAPM (Capital Asset Pricing Model): la prima por riesgo de un título = βi × prima de riesgo del mercado. Si CAPM es válido, el intercepto αi debe ser cero.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: A diferencia del modelo con intercepto, en la regresión a través del origen: (1) Σûi no necesariamente = 0, (2) el r² convencional puede ser negativo, (3) gl para σˆ² son n − 1 en lugar de n − 2.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\nIMPLICACIÓN: A menos que exista expectativa teórica muy sólida, es aconsejable incluir el intercepto. Si resulta no significativo, para efectos prácticos se tiene regresión a través del origen.", "c": "C55A11", "b": true}]}, {"text": "Deben ser obvias las diferencias entre estos dos conjuntos de fórmulas: en el modelo sin término de intercepto se utilizan sumas de cuadrados simples y productos cruzados, pero en el modelo con intercepto, se utilizan sumas de cuadrados ajustadas (de la media) y productos cruzados. Segundo, los gl para calcular σˆ² son (n − 1) en el primer caso y (n − 2) en el segundo. Aunque el modelo sin intercepto o con intercepto cero puede ser apropiado en algunas ocasiones, la suma de residuos ûi, que es siempre cero en el modelo con intercepto (el modelo convencional), no necesita serlo cuando ese término está ausente. Además, r², el coeficiente de determinación presentado en el capítulo 3, que siempre es no negativo en el modelo convencional, en ocasiones puede volverse negativo en el modelo sin intercepto.", "title": "Diferencias clave entre modelos con y sin intercepto", "eq": "¿Por qué el r² convencional no es apropiado para la regresión a través del origen?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Modelo sin intercepto usa sumas simples (ΣXiYi, ΣXi²). Modelo con intercepto usa sumas ajustadas (Σxiyi, Σxi²). El r² convencional puede ser negativo sin intercepto.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nCONCEPTO CLAVE: Para regresión a través del origen se usa el r² simple = (ΣXiYi)²/(ΣXi²·ΣYi²), basado en sumas no corregidas por la media. No es directamente comparable con el r² convencional.", "c": "2E75B6", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: Las fórmulas MCO del capítulo 3 (ecuaciones 3.1.6, 3.3.1, 3.3.5) se modifican cuando no hay intercepto.", "c": "006B6B", "b": true}]}, {"text": "Las unidades con que se mide la variable regresada y la(s) variable(s) regresora(s) influyen de algún modo en los resultados de la regresión. Definamos Y*i = w1Yi y X*i = w2Xi, donde w1 y w2 son constantes, denominadas factores de escala. Las relaciones entre los parámetros son: βˆ*2 = (w1/w2)βˆ2, βˆ*1 = w1βˆ1, σˆ*² = w1²σˆ², var(βˆ*2) = (w1/w2)²var(βˆ2), y r²xy = r²x*y*. Es decir, r² es invariable respecto de los cambios en las unidades de medición.", "title": "Efecto de las escalas y unidades de medición", "eq": "¿Por qué r² no cambia cuando se transforman las unidades de medición de X y Y?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Al reescalar Y por w1 y X por w2: pendiente se multiplica por w1/w2, intercepto por w1, varianza residual por w1², pero r² permanece invariable (es adimensional).", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: IDPB vs PIB: en miles de millones, β2 = 0.2535. Al cambiar IDPB a millones (w1=1000) y PIB en miles de millones (w2=1), β2 = 253.524. Mismo resultado, diferentes unidades.", "c": "1A5C38", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: El coeficiente de la pendiente β2 es una tasa de cambio medida en (unidades de Y)/(unidades de X). Al interpretar, siempre se debe considerar las unidades de medición.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\nDISTINCIÓN: Si w1 = w2 (misma escala para ambas), la pendiente y su error estándar no cambian, pero el intercepto se multiplica por w1.", "c": "C00000", "b": true}]}, {"text": "Se dice que una variable es estandarizada si se resta el valor de la media de esta variable de sus valores individuales y se divide esa diferencia entre la desviación estándar de la variable. Así, Y*i = (Yi − Ȳ)/SY y X*i = (Xi − X̄)/SX. Una propiedad interesante de una variable estandarizada es que el valor de su media siempre es cero y que su desviación estándar siempre es 1. En la regresión sobre variables estandarizadas, el intercepto siempre es cero y el coeficiente de la pendiente β*2, conocido como coeficiente beta, se relaciona con el coeficiente original mediante βˆ*2 = βˆ2(Sx/Sy).", "title": "Regresión con variables estandarizadas y coeficientes beta", "eq": "¿Qué ventaja práctica ofrecen los coeficientes beta sobre los coeficientes de regresión originales?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Variables estandarizadas: media = 0, desviación estándar = 1. Coeficiente beta: βˆ*2 = βˆ2(Sx/Sy). Mide el cambio en desviaciones estándar de Y por una desviación estándar de X.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: La regresión estandarizada siempre pasa por el origen (intercepto = 0). Los coeficientes beta permiten comparar la importancia relativa de diferentes regresoras cuando tienen distintas unidades.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: En regresión múltiple (caps. 7-8), los coeficientes beta son especialmente útiles para comparar la fuerza relativa de múltiples regresoras con diferentes escalas.", "c": "2D2D8F", "b": true}]}, {"text": "Considere el siguiente modelo, conocido como modelo de regresión exponencial: Yi = β1Xi^β2·e^ui, que puede expresarse también como ln Yi = ln β1 + β2 ln Xi + ui, o equivalentemente ln Yi = α + β2 ln Xi + ui, donde α = ln β1. Este modelo es lineal en los parámetros α y β2, lineal en los logaritmos de las variables Y y X, y se estima por regresión MCO. Debido a esta linealidad, tales modelos se denominan modelos log-log, doble-log o log-lineales.", "title": "El modelo log-lineal o de elasticidad constante", "eq": "¿Por qué β2 en el modelo log-lineal se interpreta directamente como elasticidad?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Modelo log-lineal: ln Y = α + β2 ln X + u. El coeficiente β2 mide la elasticidad de Y respecto de X: el cambio porcentual en Y ante un cambio porcentual de 1% en X. Es constante a lo largo de toda la curva.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Para gasto en bienes duraderos vs gasto total: ln GASBD = −7.54 + 1.63 ln GCPERT. Elasticidad = 1.63: si gasto total ↑ 1%, gasto en durables ↑ 1.63%. Bien 'elástico'.", "c": "1A5C38", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: A diferencia del modelo lineal (donde la elasticidad varía según el punto), en el modelo log-log la elasticidad β2 es constante. Por eso se llama 'modelo de elasticidad constante'.", "c": "C00000", "b": true}, {"t": "◆ CONTEXTUAL:\nIMPLICACIÓN: Si β2 > 1: bien elástico (lujo). Si β2 < 1: bien inelástico (necesidad). Si β2 = 1: elasticidad unitaria.", "c": "C55A11", "b": true}]}, {"text": "Los modelos como ln Yt = β1 + β2t + ut se denominan modelos semilog porque sólo una variable (en este caso, la regresada) aparece en forma logarítmica. Para fines descriptivos, un modelo en el cual la variable regresada es logarítmica se denomina modelo log-lin. En este modelo, el coeficiente de la pendiente mide el cambio proporcional constante o relativo en Y para un cambio absoluto dado en el valor de la regresora. Es decir, 100 por β2 da como resultado la tasa de crecimiento en Y; 100 por β2 se conoce en la bibliografía como la semielasticidad de Y respecto de X.", "title": "Modelo semilogarítmico log-lin y tasa de crecimiento", "eq": "¿Cómo se obtiene la tasa de crecimiento compuesta a partir de la tasa instantánea del modelo log-lin?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Modelo log-lin: ln Y = β1 + β2X + u. 100·β2 = tasa de crecimiento instantánea (%). β2 = semielasticidad: cambio proporcional en Y por cambio unitario absoluto en X.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nDISTINCIÓN: Tasa instantánea vs tasa compuesta: tasa compuesta = [antilog(βˆ2) − 1]×100. La tasa compuesta es ligeramente mayor que la instantánea por el efecto de composición.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Gasto en servicios: ln GES = 8.3226 + 0.00705t. Tasa trimestral instantánea = 0.705%. Tasa compuesta = [antilog(0.00705)−1]×100 = 0.708%. Tasa anual ≈ 2.82%.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nCONEXIÓN CONCEPTUAL: El modelo log-lin se deriva de la fórmula de interés compuesto Yt = Y0(1+r)^t tomando logaritmos.", "c": "5B2C8C", "b": true}]}, {"text": "A diferencia del modelo de crecimiento recién estudiado, en el cual nos interesaba encontrar el crecimiento porcentual en Y ante un cambio unitario absoluto en X, ahora deseamos encontrar el cambio absoluto en Y debido a un cambio porcentual en X. Un modelo que cumple este propósito se escribe como Yi = β1 + β2 ln Xi + ui. Con fines descriptivos se le llama modelo lin-log. El coeficiente β2 = ΔY/(ΔX/X): el cambio absoluto en Y es igual a la pendiente multiplicada por el cambio relativo en X. Si ΔX/X cambia en 0.01 (1%), el cambio absoluto en Y es 0.01(β2).", "title": "Modelo semilogarítmico lin-log y la ley de Engel", "eq": "¿Cómo se interpreta correctamente β2 en el modelo lin-log, y por qué se divide entre 100?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Modelo lin-log: Y = β1 + β2 ln X + u. β2 = cambio absoluto en Y / cambio proporcional en X. Para un cambio de 1% en X, Y cambia en β2/100 unidades.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: Ley de Engel: el gasto en alimentos tiende a incrementarse en progresión aritmética mientras el gasto total aumenta en progresión geométrica. El modelo lin-log captura este patrón.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Gasto alimentario India: GasAli = −1283.9 + 257.3 ln GasTot. Si gasto total ↑ 1%, gasto alimentario ↑ 257.3/100 = 2.57 rupias.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nDISTINCIÓN: En el modelo log-lin, β2 mide tasa de crecimiento (% de Y por unidad de X). En lin-log, β2 mide cambio absoluto (unidades de Y por % de X). Son modelos complementarios.", "c": "C00000", "b": true}]}, {"text": "Los modelos del siguiente tipo se conocen como modelos recíprocos: Yi = β1 + β2(1/Xi) + ui. A pesar de que este modelo es no lineal en la variable X porque entra inversamente o en forma recíproca, el modelo es lineal en β1 y β2, y, por consiguiente, es un modelo de regresión lineal. Este modelo tiene las siguientes características: a medida que X aumenta indefinidamente, el término β2(1/X) se acerca a cero y Y se aproxima al valor límite o asintótico β1.", "title": "El modelo recíproco y la curva de Phillips", "eq": "¿Qué tipo de fenómenos económicos se representan mejor con un modelo recíproco que con uno lineal?", "anns": [{"t": "◆◆◆ CRÍTICO:\nCONCEPTO CLAVE: Modelo recíproco: Y = β1 + β2(1/X) + u. Es lineal en los parámetros. Cuando X → ∞, Y → β1 (valor asintótico). Si β2 > 0, la pendiente dY/dX = −β2/X² es siempre negativa.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nAUTOR / TEORÍA: La curva de Phillips (1958) relaciona cambios salariales con desempleo con forma de modelo recíproco. La versión moderna (Blanchard): πt − πt−1 = β1 + β2·UNt + ut, donde la tasa natural UN = −βˆ1/βˆ2.", "c": "2E75B6", "b": true}, {"t": "◆◆ IMPORTANTE:\nEJEMPLO: Mortalidad infantil vs PIB per cápita: MI = 81.79 + 27237(1/PIBPC). Asíntota = 82 muertes/1000. Al principio MI baja drásticamente con ingreso, luego se estabiliza.", "c": "1A5C38", "b": true}, {"t": "◆ CONTEXTUAL:\nIMPLICACIÓN: Para la curva de Phillips con datos de EU 1960-2006: tasa natural de desempleo estimada = 3.7844/0.6385 ≈ 5.93%, consistente con estimaciones de 5-6%.", "c": "C55A11", "b": true}]}, {"text": "En este capítulo se analizaron las distintas formas funcionales que un modelo empírico puede tomar, incluso dentro de los confines de los modelos de regresión lineal en los parámetros. La elección de una forma funcional particular puede ser relativamente fácil para el caso de dos variables, pues se pueden graficar las variables y tener así una ligera idea respecto del modelo adecuado. Algunas sugerencias: la teoría tal vez sugiera una forma funcional particular; es una buena costumbre calcular la tasa de cambio y conocer la elasticidad; los coeficientes del modelo escogido deberán satisfacer determinadas expectativas a priori; en general, no se debe sobrevaluar la medida de r².", "title": "Criterios para elegir la forma funcional apropiada", "eq": "¿Por qué no se deben comparar directamente los r² de un modelo log-lineal y uno lineal?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Solo se pueden comparar r² si las variables dependientes son idénticas. Si una regresión usa Y y otra ln Y, sus r² NO son comparables.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Criterios de selección: (1) justificación teórica, (2) signos esperados de coeficientes, (3) significancia estadística, (4) r² comparable. La teoría y los signos importan más que un r² alto.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n→ REAPARECE EN: En el capítulo 13 se estudiarán pruebas formales de especificación del modelo y criterios más rigurosos para seleccionar la forma funcional.", "c": "2D2D8F", "b": true}]}, {"text": "Se debe prestar mucha atención al término de error al transformar un modelo para el análisis de regresión. De lo contrario, una aplicación a ciegas de MCO al modelo transformado no producirá un modelo con las propiedades estadísticas deseables. Para el modelo Yi = β1Xi^β2·ui, al tomar logaritmos se obtiene ln Yi = α + β2 ln Xi + ln ui, y se debe suponer que ln ui ~ N(0, σ²). Para el modelo Yi = β1Xi^β2·e^ui, se obtiene ln Yi = α + β2 ln Xi + ui directamente con ui normal. El modelo Yi = β1Xi^β2 + ui es intrínsecamente no lineal en los parámetros porque ln(A + B) ≠ ln A + ln B.", "title": "Error estocástico: aditivo versus multiplicativo", "eq": "¿Por qué la naturaleza del error estocástico (aditivo vs multiplicativo) determina si el modelo transformado es estimable por MCO?", "anns": [{"t": "◆◆◆ CRÍTICO:\nDISTINCIÓN: Error multiplicativo (Yi = β1Xi^β2·e^ui): al tomar log, ui queda aditivo y el modelo es lineal → MCO aplicable. Error aditivo (Yi = β1Xi^β2 + ui): ln(A+B) ≠ ln A + ln B → modelo intrínsecamente no lineal.", "c": "C00000", "b": true}, {"t": "◆◆ IMPORTANTE:\nIMPLICACIÓN: Si el error se especifica como multiplicativo y se toman logaritmos, las pruebas de normalidad deben aplicarse a los residuos del modelo transformado (ln ûi), no a los originales.", "c": "C55A11", "b": true}, {"t": "◆ CONTEXTUAL:\n↩ RETOMA: Los supuestos MELI del MCO (capítulo 3) requieren que el término de error tenga media cero, varianza constante y ausencia de autocorrelación.", "c": "006B6B", "b": true}]}], "retrieval": {"q": ["¿Cuáles son las principales diferencias entre la regresión a través del origen y la regresión con intercepto?", "Compare e interprete los modelos log-log, log-lin y lin-log, indicando qué mide el coeficiente de pendiente en cada uno.", "Explique el modelo recíproco y su aplicación a la curva de Phillips.", "¿Qué criterios se deben usar para elegir la forma funcional apropiada de un modelo de regresión?"], "a": ["Las principales diferencias son: (1) el estimador MCO usa sumas simples (ΣXiYi/ΣXi²) vs sumas ajustadas por la media (Σxiyi/Σxi²); (2) los gl para σˆ² son n−1 vs n−2; (3) la suma de residuos no es necesariamente cero sin intercepto; (4) el r² convencional puede ser negativo sin intercepto, por lo que se usa el r² simple. A menos que haya fuerte razón teórica (como CAPM), es mejor incluir el intercepto.", "Modelo log-log (ln Y = α + β2 ln X): β2 = elasticidad constante (cambio % en Y por 1% de cambio en X). Modelo log-lin (ln Y = β1 + β2X): 100·β2 = tasa de crecimiento (cambio % en Y por cambio unitario en X), semielasticidad. Modelo lin-log (Y = β1 + β2 ln X): β2/100 = cambio absoluto en Y por 1% de cambio en X. El log-log es popular en demanda (elasticidad-precio); el log-lin para tasas de crecimiento; el lin-log para gastos de Engel.", "El modelo recíproco Y = β1 + β2(1/X) + u tiene un valor asintótico β1 cuando X → ∞. Es lineal en los parámetros. La curva de Phillips clásica relaciona cambios salariales con desempleo con esta forma. La versión moderna (πt − πt−1 = β1 + β2·UNt + ut) permite estimar la tasa natural de desempleo como UN = −βˆ1/βˆ2. Para EU 1960-2006, UN ≈ 5.93%.", "Los criterios son: (1) la teoría debe sugerir la forma funcional; (2) calcular pendientes y elasticidades para cada modelo; (3) los signos de los coeficientes deben satisfacer expectativas a priori; (4) más de un modelo puede ajustarse bien, pero solo comparar r² si la variable dependiente es la misma; (5) no sobrevaluar r²: la justificación teórica y los signos importan más; (6) verificar supuestos del MCRL sobre los residuos del modelo seleccionado."]}}], "flujo": {"sesiones": [{"nombre": "Pre-lectura", "tiempo": "7-10 min"}, {"nombre": "Puente a la tesis", "tiempo": "10-12 min"}, {"nombre": "Lectura anotada (6 capítulos)", "tiempo": "120-150 min"}, {"nombre": "Retrieval activo", "tiempo": "25-30 min"}, {"nombre": "Glosario y protocolo", "tiempo": "15-20 min"}], "revision": [{"sesion": "Sesión 1 — Hoy", "tiempo": "25-30 min", "fecha": "2026-04-09", "tareas": "Retrieval de los 6 capítulos sin mirar respuestas. Leer glosario completo. Revisar puente. Foco en: MCO, supuestos MCRL, pruebas de hipótesis."}, {"sesion": "Sesión 2 — 7 días", "tiempo": "15-20 min", "fecha": "2026-04-16", "tareas": "Retrieval de secciones falladas. Reconstruir el hilo lógico: FRP → FRM → MCO → MELI → normalidad → inferencia. Escribir cómo usarás estos métodos en tu tesis."}, {"sesion": "Sesión 3 — 30 días", "tiempo": "10-15 min", "fecha": "2026-05-09", "tareas": "Glosario y retrieval de los conceptos más difíciles. Resolver ejercicios sin consultar el texto. Decidir qué técnicas aplicarás en tu investigación."}]}, "reflexiones": [{"emoji": "📖", "titulo": "Primera impresión", "hint": "¿Qué te pareció más desafiante: la notación matemática, la lógica de las pruebas de hipótesis, o la interpretación económica de los coeficientes?"}, {"emoji": "🔗", "titulo": "Conexiones doctorales", "hint": "¿Qué variables de tu investigación podrías modelar con regresión lineal? ¿Cumplirían los supuestos del MCRL?"}, {"emoji": "❓", "titulo": "Preguntas abiertas", "hint": "¿Qué pasa cuando los supuestos se violan? ¿Cuándo es preferible un modelo no lineal? ¿Cómo se eligen las variables explicativas?"}, {"emoji": "📚", "titulo": "Textos a explorar", "hint": "¿Necesitas profundizar en regresión múltiple (Cap. 7-8), heteroscedasticidad (Cap. 11), o autocorrelación (Cap. 12)?"}, {"emoji": "✅", "titulo": "Acciones concretas", "hint": "¿Replicarás algún ejemplo en software estadístico? ¿Aplicarás MCO a tus propios datos?"}, {"emoji": "🔍", "titulo": "Dudas activas", "hint": "¿Entiendes la diferencia entre R² y R² ajustado? ¿Entre error tipo I y tipo II? ¿Por qué F = t² en el caso bivariado?"}, {"emoji": "💬", "titulo": "Agenda para discusión", "hint": "¿Qué preguntarías a tu profesor sobre la aplicación de estos métodos a tu tema de investigación?"}, {"emoji": "📝", "titulo": "Notas libres", "hint": "Espacio libre para ideas, intuiciones o conexiones que no encajan en las categorías anteriores."}], "mapa": {"instruccion": "Este mapa te ayuda a posicionar el texto de Gujarati dentro de tu corpus doctoral. Los capítulos 1-6 son la base de toda la econometría aplicada. Identifica convergencias, tensiones y preguntas abiertas con otros textos cuantitativos que has leído.", "converge": {"titulo": "↔ Converge con", "hint": "Piensa en otros textos de métodos cuantitativos, estadística aplicada o metodología de investigación que utilizan regresión como herramienta central."}, "tension": {"titulo": "⇄ Entra en tensión con", "hint": "Considera enfoques cualitativos, interpretativos o de complejidad que cuestionan la reducción de fenómenos sociales a relaciones lineales estimables."}, "preguntas": {"titulo": "→ Abre preguntas hacia", "hint": "¿Qué limitaciones del modelo lineal bivariado te llevan a necesitar técnicas más avanzadas?"}, "preguntas_iniciales": ["¿Es legítimo aplicar modelos lineales a fenómenos organizacionales que son inherentemente complejos y no lineales?", "¿Cómo se reconcilia la econometría clásica (frecuentista) con los enfoques bayesianos cada vez más populares?", "¿Qué sucede con la inferencia cuando los datos son observacionales y no experimentales — puede la regresión sustituir al experimento controlado?"]}, "glosario": [{"concepto": "Análisis de regresión", "peso": "critico", "definicion": "Estudio de la dependencia estadística de una variable (dependiente) respecto de una o más variables (explicativas), con el objetivo de estimar o predecir la media condicional poblacional de la primera dados los valores fijos de las segundas", "anidamiento": "Es la herramienta fundamental de la econometría. Contiene como casos especiales la regresión simple (bivariada) y la regresión múltiple", "tension": "Establece dependencia estadística pero no causalidad; la causalidad requiere teoría a priori", "origen": "Francis Galton (1886), reinterpretado en el sentido moderno por la estadística del siglo XX"}, {"concepto": "Función de Regresión Poblacional (FRP)", "peso": "critico", "definicion": "Expresión matemática E(Y|Xᵢ) = f(Xᵢ) que describe cómo la media condicional de la variable dependiente varía en función de los valores de la variable explicativa; en el caso lineal, E(Y|Xᵢ) = β₁ + β₂Xᵢ", "anidamiento": "Es el objeto teórico que la Función de Regresión Muestral (FRM) busca estimar. Contiene los parámetros poblacionales β₁ y β₂", "tension": "Nunca se conoce en la práctica porque requiere datos de toda la población; solo puede estimarse mediante la FRM", "origen": "Formalización del concepto de regresión de Galton en el marco de la estadística matemática moderna"}, {"concepto": "Perturbación estocástica (uᵢ)", "peso": "critico", "definicion": "Variable aleatoria no observable que captura la desviación de cada observación individual Yᵢ respecto de la media condicional E(Y|Xᵢ), representando el efecto conjunto de todas las variables omitidas del modelo, errores de medición y aleatoriedad intrínseca", "anidamiento": "Componente de la FRP estocástica Yᵢ = β₁ + β₂Xᵢ + uᵢ. Su contraparte muestral es el residual ûᵢ", "tension": "El supuesto E(uᵢ|Xᵢ) = 0 es fundamental pero puede violarse si hay variables omitidas correlacionadas con X", "origen": "Formalizado en el modelo clásico de regresión lineal (Gauss-Markov)"}, {"concepto": "Función de Regresión Muestral (FRM)", "peso": "critico", "definicion": "Contraparte muestral de la FRP, expresada como Ŷᵢ = β̂₁ + β̂₂Xᵢ, donde β̂₁ y β̂₂ son estimadores de los parámetros poblacionales calculados a partir de datos muestrales disponibles", "anidamiento": "Estima la FRP. Sus estimadores se obtienen mediante métodos como MCO (Capítulo 3). Incluye la forma estocástica Yᵢ = β̂₁ + β̂₂Xᵢ + ûᵢ", "tension": "Diferentes muestras producen diferentes FRM debido a fluctuaciones muestrales; ninguna coincide exactamente con la FRP", "origen": "Concepto central de la inferencia estadística aplicada al análisis de regresión"}, {"concepto": "Linealidad en los parámetros", "peso": "critico", "definicion": "Propiedad de un modelo de regresión donde los coeficientes β aparecen elevados solo a la primera potencia y no están multiplicados entre sí, independientemente de la forma en que aparezcan las variables explicativas X", "anidamiento": "Define lo que se entiende por 'modelo de regresión lineal' en econometría. Los modelos no lineales en los parámetros requieren métodos de estimación diferentes (Capítulo 14)", "tension": "Un modelo puede ser no lineal en X pero lineal en β (ej: Y = β₁ + β₂X²), y aún se estima con MCO", "origen": "Distinción fundamental en la clasificación de modelos econométricos"}, {"concepto": "MCO (Mínimos Cuadrados Ordinarios)", "peso": "critico", "definicion": "Método de estimación que obtiene los estimadores de los parámetros de regresión minimizando la suma de los cuadrados de los residuos (Σû²i). Atribuido a Carl Friedrich Gauss (1821), produce estimadores con propiedades óptimas bajo los supuestos del MCRL.", "anidamiento": "Método de estimación → Regresión lineal → Inferencia estadística", "tension": "Eficiente bajo homoscedasticidad, pierde optimalidad con heteroscedasticidad o autocorrelación", "origen": "Carl Friedrich Gauss (1821)"}, {"concepto": "MELI (Mejor Estimador Lineal Insesgado)", "peso": "critico", "definicion": "Propiedad de un estimador que es simultáneamente lineal (función lineal de las observaciones), insesgado (su valor esperado iguala al parámetro verdadero) y de varianza mínima dentro de la clase de estimadores lineales insesgados. El teorema de Gauss-Markov demuestra que MCO es MELI bajo los supuestos del MCRL.", "anidamiento": "Propiedad de MCO → Teorema de Gauss-Markov → Optimalidad de estimadores", "tension": "MELI no garantiza optimalidad entre estimadores no lineales; con normalidad se amplía a MEI", "origen": "Gauss (1821) para MCO, Markov (1900) para la prueba de varianza mínima"}, {"concepto": "Teorema de Gauss-Markov", "peso": "critico", "definicion": "Teorema fundamental que establece que, dados los supuestos del modelo clásico de regresión lineal (linealidad, X fija, E(ui)=0, homoscedasticidad, no autocorrelación), los estimadores MCO tienen varianza mínima entre todos los estimadores lineales insesgados. No requiere normalidad de las perturbaciones.", "anidamiento": "Fundamenta MCO → Supuestos MCRL → Base teórica de la regresión", "tension": "Válido sin normalidad, pero sin normalidad no se pueden derivar distribuciones exactas para inferencia", "origen": "Gauss (1821) y Markov (1900)"}, {"concepto": "Supuestos del modelo clásico de regresión lineal (MCRL)", "peso": "critico", "definicion": "Conjunto de siete condiciones que fundamentan la regresión MCO: (1) linealidad en parámetros, (2) X fija o independiente de u, (3) E(ui)=0, (4) homoscedasticidad var(ui)=σ², (5) no autocorrelación cov(ui,uj)=0, (6) n > número de parámetros, (7) variabilidad en X. Violar cualquiera afecta las propiedades de MCO.", "anidamiento": "Base del MCRL → Condiciones para Gauss-Markov → Fundamento de toda la regresión clásica", "tension": "Son idealización teórica; en la práctica se violan con frecuencia, originando capítulos enteros del libro dedicados a cada violación", "origen": "Gauss (1821), formalización clásica en econometría"}, {"concepto": "Distribución normal de los errores (MCRLN)", "peso": "critico", "definicion": "Supuesto adicional al MCRL que especifica ui ~ NID(0, σ²): las perturbaciones son normal e independientemente distribuidas. Justificado por el Teorema Central del Límite. Permite derivar distribuciones exactas de los estimadores MCO y habilita las pruebas t, F y chi-cuadrada para inferencia.", "anidamiento": "Supuesto de normalidad → MCRLN → Inferencia estadística en regresión", "tension": "Crucial en muestras pequeñas; en muestras grandes las aproximaciones asintóticas relajan esta necesidad", "origen": "Formalizado en la tradición de Gauss-Laplace; TCL como justificación teórica"}, {"concepto": "Intervalo de confianza", "peso": "critico", "definicion": "Rango construido alrededor de un estimador puntual con probabilidad 1−α de contener al verdadero valor del parámetro poblacional. Para β2: βˆ2 ± tα/2·ee(βˆ2) con n−2 grados de libertad.", "anidamiento": "Se construye usando la distribución t (σ² desconocida) o normal (σ² conocida). Se relaciona con la prueba de hipótesis como método complementario.", "tension": "Un intervalo estrecho indica alta precisión del estimador; uno amplio, gran incertidumbre. La interpretación frecuentista de largo plazo no es intuitiva.", "origen": "Jerzy Neyman formalizó la teoría de intervalos de confianza en 1937."}, {"concepto": "Prueba de hipótesis (t y F)", "peso": "critico", "definicion": "La prueba t evalúa si un coeficiente individual difiere significativamente de un valor hipotético: t = (βˆ2 − β2*)/ee(βˆ2). La prueba F evalúa la significancia global del modelo comparando variación explicada vs residual. Para dos variables: F(1, n−2) = t².", "anidamiento": "Ambas pruebas requieren normalidad de los errores. Se complementan con el valor p para evitar la selección arbitraria de α.", "tension": "Significancia estadística no implica significancia práctica. Con muestras grandes, casi todo es 'significativo' pero puede ser sustancialmente trivial.", "origen": "R. A. Fisher (prueba de significancia); Neyman-Pearson (teoría de errores tipo I y II); W. S. Gosset/Student (distribución t)."}, {"concepto": "R² (coeficiente de determinación)", "peso": "critico", "definicion": "Proporción de la variación total en Y explicada por el modelo de regresión: r² = SCE/SCT = 1 − SCR/SCT. Varía entre 0 y 1 en modelos con intercepto. Es invariante ante cambios de escala.", "anidamiento": "Se descompone en la tabla ANOVA. No es apropiado comparar r² de modelos con distintas variables dependientes (Y vs ln Y). En regresión a través del origen, el r² convencional puede ser negativo.", "tension": "Un r² alto no garantiza un buen modelo. Un r² bajo no implica un modelo inútil. No se debe sobrevaluar: la justificación teórica y los signos de coeficientes importan más.", "origen": "Karl Pearson desarrolló el concepto de correlación. R² = r² en regresión bivariada."}, {"concepto": "Análisis de varianza (ANOVA)", "peso": "critico", "definicion": "Descomposición de la variación total de Y en componentes: SCT = SCE + SCR. La tabla ANOVA presenta sumas de cuadrados, grados de libertad y sumas de cuadrados promedio. La razón F = SCP(SCE)/SCP(SCR) prueba H0: β2 = 0.", "anidamiento": "Fundamenta la prueba F. En el modelo de dos variables, F(1,n−2) = t². En regresión múltiple, la prueba F evalúa la significancia conjunta de todos los coeficientes.", "tension": "Para dos variables, la prueba F no agrega información sobre la prueba t. Su verdadero poder se manifiesta en regresión múltiple para probar hipótesis conjuntas.", "origen": "R. A. Fisher desarrolló el análisis de varianza como método general para comparar variaciones."}, {"concepto": "Predicción (media e individual)", "peso": "critico", "definicion": "Predicción media: estima E(Y|X0) = β1 + β2X0, con varianza σ²[1/n + (X0−X̄)²/Σxi²]. Predicción individual: estima Y0 particular, con varianza adicional σ² por la variabilidad de ui. Ambas usan la distribución t para intervalos de confianza.", "anidamiento": "La varianza de predicción es mínima en X0 = X̄ y crece al alejarse. No extrapolar lejos del rango muestral.", "tension": "El intervalo individual siempre es más amplio que el de la media. La capacidad predictiva decrece rápidamente al alejarse de X̄.", "origen": "Derivada del marco de mínimos cuadrados ordinarios establecido por Gauss y desarrollado por Fisher."}], "glosario_mapa": {"anidamiento": [{"concepto": "Modelo de Regresión Lineal", "nivel": 0, "hijos": ["FRP", "FRM", "MCO", "Supuestos del MCRL"]}, {"concepto": "MCO", "nivel": 1, "hijos": ["MELI", "R²", "Error estándar"]}, {"concepto": "Supuestos del MCRL", "nivel": 1, "hijos": ["Homocedasticidad", "No autocorrelación", "Normalidad"]}, {"concepto": "Normalidad (MCRLN)", "nivel": 2, "hijos": ["Distribución t", "Distribución F", "Chi-cuadrado"]}, {"concepto": "Inferencia estadística", "nivel": 0, "hijos": ["Intervalo de confianza", "Prueba de hipótesis", "ANOVA", "Predicción"]}], "tensiones": [{"par": "FRP ↔ FRM", "desc": "La FRP es el objetivo teórico inobservable; la FRM es la aproximación empírica que siempre tiene error muestral"}, {"par": "Estimador ↔ Estimación", "desc": "El estimador es la fórmula/regla (variable aleatoria); la estimación es el valor numérico concreto obtenido con datos específicos"}, {"par": "Significancia estadística ↔ Significancia práctica", "desc": "Un efecto puede ser estadísticamente significativo pero sustantivamente irrelevante, y viceversa con muestras pequeñas"}, {"par": "R² alto ↔ Buen modelo", "desc": "Un R² alto no garantiza un modelo correcto (puede ser espurio), y un R² bajo no invalida un modelo teóricamente sólido"}, {"par": "Linealidad en parámetros ↔ Linealidad en variables", "desc": "MCO requiere solo linealidad en parámetros; modelos exponenciales y potenciales pueden linealizarse con transformaciones logarítmicas"}]}, "defaultCards": [{"front": "¿Qué es el análisis de regresión según su definición moderna?", "back": "Es el estudio de la dependencia de una variable (dependiente) respecto de una o más variables (explicativas), con el objetivo de estimar o predecir el valor medio poblacional de la primera en términos de los valores conocidos de las segundas.", "type": "basic"}, {"front": "¿Qué es el método de Mínimos Cuadrados Ordinarios (MCO)?", "back": "Es un método de estimación que obtiene los valores de los parámetros de la regresión minimizando la suma de los cuadrados de los residuos (diferencias entre valores observados y estimados). Fue desarrollado por Carl Friedrich Gauss.", "type": "basic"}, {"front": "¿Qué significa que un estimador sea MELI (Mejor Estimador Lineal Insesgado)?", "back": "Significa que, dentro de la clase de estimadores que son lineales en Y e insesgados, tiene la varianza mínima. Esto es lo que garantiza el teorema de Gauss-Markov cuando se cumplen los supuestos del MCRL.", "type": "basic"}, {"front": "¿Qué es la Función de Regresión Poblacional (FRP)?", "back": "Es la relación funcional teórica entre la media condicional de Y y los valores de X en la población completa: E(Y|Xi) = β₁ + β₂Xi. Es inobservable y se estima mediante la FRM.", "type": "basic"}, {"front": "¿Qué es la Función de Regresión Muestral (FRM)?", "back": "Es la contraparte empírica de la FRP, estimada a partir de datos muestrales: Ŷi = β̂₁ + β̂₂Xi. Sus coeficientes son estimaciones puntuales de los parámetros poblacionales.", "type": "basic"}, {"front": "¿Qué mide el coeficiente de determinación R²?", "back": "Mide la proporción o porcentaje de la variación total en Y que es explicada por el modelo de regresión. Varía entre 0 y 1: R² = SEC/STC = 1 − SRC/STC. Un R² de 0.8 indica que el 80% de la variación en Y es explicada por X.", "type": "basic"}, {"front": "¿Qué es la perturbación estocástica (término de error u)?", "back": "Es una variable aleatoria que representa todos los factores que afectan a Y pero no están incluidos explícitamente en el modelo. Captura: variables omitidas, errores de medición, aleatoriedad intrínseca del comportamiento humano y forma funcional incorrecta.", "type": "basic"}, {"front": "¿Qué es un intervalo de confianza?", "back": "Es un rango construido alrededor de un estimador puntual tal que, en muestreo repetido, contiene al verdadero parámetro poblacional con una probabilidad especificada (1 − α). Por ejemplo, un IC al 95% significa que en 95 de cada 100 muestras el intervalo contendría al verdadero parámetro.", "type": "basic"}, {"front": "¿Cuál es la diferencia entre un estimador y una estimación?", "back": "El estimador es la fórmula o regla de estimación (es una variable aleatoria, cambia de muestra a muestra). La estimación es el valor numérico concreto que se obtiene al aplicar esa fórmula a una muestra específica de datos.", "type": "basic"}, {"front": "¿Cuál es la diferencia entre la hipótesis nula (H₀) y la hipótesis alternativa (H₁)?", "back": "H₀ es la hipótesis que se asume verdadera inicialmente y que se somete a prueba (ej: β₂ = 0). H₁ es la hipótesis que se acepta si la evidencia muestral rechaza H₀ (ej: β₂ ≠ 0). La lógica es asimétrica: se puede rechazar H₀ pero nunca 'aceptar' H₀ con certeza.", "type": "basic"}, {"front": "¿Cuál es la diferencia entre error tipo I y error tipo II?", "back": "Error tipo I (α): rechazar H₀ cuando es verdadera (falso positivo). Error tipo II (β): no rechazar H₀ cuando es falsa (falso negativo). Reducir uno aumenta el otro si el tamaño muestral se mantiene constante.", "type": "basic"}, {"front": "¿Cuál es la diferencia entre significancia estadística y significancia práctica?", "back": "Significancia estadística indica que un coeficiente es diferente de cero con alta probabilidad (valor p bajo). Significancia práctica indica que el efecto es lo suficientemente grande como para importar en el contexto real. Un efecto puede ser estadísticamente significativo pero sustantivamente trivial, especialmente con muestras grandes.", "type": "basic"}, {"front": "¿Cuál es la diferencia entre correlación y regresión?", "back": "Correlación mide el grado de asociación lineal entre dos variables (simétrica: rXY = rYX). Regresión estudia la dependencia de una variable respecto de otra(s) para estimar su media condicional (asimétrica: Y|X ≠ X|Y). La regresión implica dirección; la correlación no.", "type": "basic"}, {"front": "¿Cuáles son los supuestos del Modelo Clásico de Regresión Lineal (MCRL)?", "back": "1) Modelo lineal en parámetros. 2) X fija en muestreo repetido (no estocástica). 3) E(ui|Xi) = 0 (media cero del error). 4) Var(ui|Xi) = σ² (homocedasticidad). 5) Cov(ui, uj) = 0 para i ≠ j (no autocorrelación). 6) Cov(ui, Xi) = 0. 7) Número de observaciones > número de parámetros.", "type": "basic"}, {"front": "¿Qué establece el teorema de Gauss-Markov?", "back": "Dados los supuestos del MCRL, los estimadores de MCO son los Mejores Estimadores Lineales Insesgados (MELI): dentro de la clase de estimadores lineales e insesgados, MCO produce los que tienen varianza mínima. No requiere normalidad.", "type": "basic"}, {"front": "¿Qué agrega el supuesto de normalidad (MCRLN) al MCRL?", "back": "Permite que los estimadores MCO tengan distribuciones exactas (normal, t, F, chi-cuadrado), habilitando la inferencia estadística con muestras pequeñas. Además, bajo normalidad MCO es no solo MELI sino el Mejor Estimador Insesgado (MEI) en toda la clase de estimadores.", "type": "basic"}, {"front": "¿Qué es la prueba de hipótesis y cuáles son sus pasos?", "back": "Es un procedimiento para verificar la verdad o falsedad de H₀ usando datos muestrales. Pasos: 1) Formular H₀ y H₁. 2) Elegir nivel de significancia α. 3) Calcular el estadístico de prueba (t o F). 4) Determinar el valor crítico o valor p. 5) Rechazar o no rechazar H₀.", "type": "basic"}, {"front": "¿Qué es ANOVA en el contexto de regresión?", "back": "Análisis de Varianza: descompone la variación total de Y (STC) en variación explicada por la regresión (SEC) y variación no explicada (SRC): STC = SEC + SRC. El estadístico F prueba la significancia global del modelo comparando la varianza explicada con la no explicada.", "type": "basic"}, {"front": "¿Qué formas funcionales extiende el Capítulo 6 más allá del modelo lineal básico?", "back": "1) Regresión por el origen (sin intercepto). 2) Modelo log-lineal o doble-log (elasticidades). 3) Modelo semilogarítmico log-lin (tasas de crecimiento). 4) Modelo semilogarítmico lin-log. 5) Modelo recíproco. Todas son lineales en parámetros aunque no en variables.", "type": "basic"}, {"front": "¿Cuál fue la contribución de Francis Galton al análisis de regresión?", "back": "Galton acuñó el término 'regresión' en 1886 al estudiar la herencia de estaturas. Descubrió que los hijos de padres extremos tendían a tener estaturas más cercanas al promedio poblacional, fenómeno que llamó 'regresión a la mediocridad'. El término se conservó pero su significado moderno es diferente.", "type": "basic"}, {"front": "¿Qué relación tienen Gauss y Markov con el método MCO?", "back": "Gauss desarrolló el método de MCO (1809). Markov contribuyó al teorema que lleva ambos nombres: el teorema de Gauss-Markov demuestra que, bajo los supuestos del MCRL, los estimadores MCO son MELI (Mejores Estimadores Lineales Insesgados).", "type": "basic"}, {"front": "¿Qué contribuyó R.A. Fisher a la inferencia estadística en regresión?", "back": "Fisher desarrolló la distribución F (que lleva su nombre), las pruebas de significancia, el concepto de máxima verosimilitud y los fundamentos de la inferencia frecuentista que permiten evaluar la significancia de los coeficientes de regresión.", "type": "basic"}, {"front": "¿Por qué regresión NO implica causalidad?", "back": "Una relación estadística, por más fuerte que sea, no establece causalidad. La regresión muestra dependencia estadística (correlación condicional), pero la dirección causal proviene de la teoría, no de los datos. Se puede encontrar una regresión significativa entre variables completamente independientes (regresión espuria).", "type": "basic"}, {"front": "¿Por qué un R² alto no garantiza un buen modelo?", "back": "Un R² alto puede ser resultado de: regresión espuria (variables con tendencia común), especificación incorrecta, o sobreajuste. Un R² bajo no invalida un modelo teóricamente sólido — en datos de corte transversal es común tener R² bajos. La calidad del modelo depende de la teoría, los signos esperados y la significancia de los coeficientes.", "type": "basic"}, {"front": "MCO minimiza la {{c1::suma de los cuadrados}} de los {{c2::residuos}}", "back": "", "type": "cloze"}, {"front": "El teorema de {{c1::Gauss-Markov}} establece que los estimadores MCO son {{c2::MELI}} cuando se cumplen los supuestos del {{c3::MCRL}}", "back": "", "type": "cloze"}, {"front": "La variación total STC se descompone en: STC = {{c1::SEC}} + {{c2::SRC}}, donde SEC es la variación {{c3::explicada}} y SRC es la variación {{c4::residual}}", "back": "", "type": "cloze"}, {"front": "En el modelo log-lineal ln(Y) = β₁ + β₂ln(X), el coeficiente β₂ mide la {{c1::elasticidad}} de Y respecto de X", "back": "", "type": "cloze"}, {"front": "Un intervalo de confianza al 95% significa que en {{c1::95}} de cada 100 muestras, el intervalo {{c2::contendría al verdadero parámetro}}", "back": "", "type": "cloze"}, {"front": "La perturbación estocástica u captura: {{c1::variables omitidas}}, {{c2::errores de medición}}, {{c3::aleatoriedad intrínseca}} y {{c4::forma funcional incorrecta}}", "back": "", "type": "cloze"}, {"front": "Bajo el supuesto de normalidad, los estimadores MCO no solo son {{c1::MELI}} sino también {{c2::MEI}} (mejores estimadores insesgados en toda la clase)", "back": "", "type": "cloze"}, {"front": "R² = {{c1::SEC/STC}} = 1 − {{c2::SRC/STC}}, y su rango es {{c3::0 ≤ R² ≤ 1}}", "back": "", "type": "cloze"}, {"front": "El estadístico t se calcula como: t = {{c1::(β̂₂ − β₂)/ee(β̂₂)}}, con {{c2::n − 2}} grados de libertad en regresión bivariada", "back": "", "type": "cloze"}, {"front": "En regresión bivariada, el estadístico F es igual a {{c1::t²}}, y prueba la {{c2::significancia global}} del modelo", "back": "", "type": "cloze"}, {"front": "En el modelo semilog ln(Y) = β₁ + β₂X, el coeficiente β₂ mide la {{c1::tasa de crecimiento}} (o cambio {{c2::porcentual}}) de Y por unidad de cambio en X", "back": "", "type": "cloze"}]};
